var CyanSkinButton = document.createElement('button');
CyanSkinButton.setAttribute('class', 'menuButton');

var CyanSkinButtonInnerText = document.createElement('span');
CyanSkinButtonInnerText.innerText = "Cyan skin";
CyanSkinButtonInnerText.style.color = '#fff';

CyanSkinButton.appendChild(CyanSkinButtonInnerText);

document.getElementById('setupCard').appendChild(document.createElement('br'))
document.getElementById('setupCard').appendChild(CyanSkinButton);

CyanSkinButton.style.backgroundColor = '#333';
CyanSkinButton.style.border = '#333';

CyanSkinButton.addEventListener('click', function() {
    window.selectSkinColor('constructor');
});
let greetings = false;

window.addEventListener("load", () => {
    const altcha_checkbox = document.querySelector("#altcha_checkbox");
    if (altcha_checkbox !== null) {
        altcha_checkbox.click();
    }

    const bottomContainer = document.querySelector("#bottomContainer");
    if (bottomContainer !== null) {
        bottomContainer.style.bottom = "10px";
    }
});

function getGreeting() {
    const hour = new Date().getHours();
    if (hour < 12) {
        return "Welcome !";
    } else if (hour < 18) {
        return "Wsp God";
    } else {
        return "Go to sleep God";
    }
}

function greeting() {
    if (!greetings) {
        greetings = true;
        const frameMsg = Object.assign(document.createElement("div"), {
            innerHTML: `${getGreeting()}`,
            style: `
                    position: fixed;
                    top: -100px;
                    left: 50%;
                    transform: translateX(-50%);
                    font-size: 2rem;
                    color: white;
                    z-index: 9999;
                    opacity: 3;
                    transition: top 0.5s ease-in-out, opacity 0.5s ease-in-out;
                    padding: 10px;
                    background-color: rgba(0, 0, 0, 0.2);
                    border: 2px solid #0000;
                    border-radius: 5px;
                    box-shadow: 0 4px 6px rgba(0, 0, 0, 0.1);
                `,
        });
        document.body.appendChild(frameMsg);
        setTimeout(function () {
            frameMsg.style.top = "7%";
            frameMsg.style.opacity = "1";
        }, 100);
        setTimeout(function () {
            frameMsg.style.top = "-100px";
            frameMsg.style.opacity = "0";
            setTimeout(function () {
                if (frameMsg) frameMsg.remove();
                greetings = false;
            }, 500);
        }, 3000);
    }
}
greeting();


