        function aJoinReq(join) {
            io.send("P", allianceNotifications[0].sid, join);
            allianceNotifications.splice(0, 1);
            updateNotifications();
        }
        function kickFromClan(sid) {
            io.send("Q", sid);
        }
        function sendJoin(index) {
            io.send("b", alliances[index].sid);
        }
        function createAlliance() {
            io.send("L", document.getElementById("allianceInput").value);
        }
        function leaveAlliance() {
            allianceNotifications = [];
            updateNotifications();
            io.send("N");
        }

        // MINIMAP:
        var lastDeath;
        var minimapData;
        var mapMarker;
        var mapPings = [];
        var tmpPing;
        function MapPing() {
            this.init = function(x, y) {
                this.scale = 0;
                this.x = x;
                this.y = y;
                this.active = true;
            };
            this.update = function(ctxt, delta) {
                if (this.active) {
                    this.scale += 0.05 * delta;
                    if (this.scale >= config.mapPingScale) {
                        this.active = false;
                    } else {
                        ctxt.globalAlpha = (1-Math.max(0, this.scale/config.mapPingScale));
                        ctxt.beginPath();
                        ctxt.arc((this.x / config.mapScale) * mapDisplay.width, (this.y / config.mapScale)
                                 * mapDisplay.width, this.scale, 0, 2 * Math.PI);
                        ctxt.stroke();
                    }
                }
            };
        }
        function pingMap(x, y) {
            for (var i = 0; i < mapPings.length; ++i) {
                if (!mapPings[i].active) {
                    tmpPing = mapPings[i];
                    break;
                }
            }
            if (!tmpPing) {
                tmpPing = new MapPing();
                mapPings.push(tmpPing);
            }
            tmpPing.init(x, y);
        }
        function updateMapMarker() {
            if (!mapMarker)
                mapMarker = {};
            mapMarker.x = myPlayer.x;
            mapMarker.y = myPlayer.y;
        }
        function updateMinimap(data) {
            minimapData = data;
        }

        // Linear interpolation helper
        function lerp(a, b, t) {
            return a + (b - a) * t;
        }

        // Reset zoom: adjusts maxScreenWidth/Height based on select value and recenters camera smoothly
        function resetZoom() {
            var el = document.getElementById('gamezoom');
            if(!el) return;
            var factor = parseFloat(el.value) || 1.5;
            var newW = config.maxScreenWidth * factor;
            var newH = config.maxScreenHeight * factor;
            console.log('[Mod] resetZoom factor=', factor, 'newW=', newW, 'newH=', newH, 'oldW=', maxScreenWidth, 'oldH=', maxScreenHeight);
            try { addChatLog('Applying zoom x' + factor, '#66ff66'); } catch(e) {}
            if (maxScreenWidth != newW || maxScreenHeight != newH) {
                maxScreenWidth = newW;
                maxScreenHeight = newH;
                resize();
                if (myPlayer) {
                    let targetCamX = myPlayer.x + (maxScreenWidth / 2) / config.playerScale;
                    let targetCamY = myPlayer.y + (maxScreenHeight / 2) / config.playerScale;
                    camX = lerp(camX, targetCamX, 0.15);
                    camY = lerp(camY, targetCamY, 0.15);
                }
            }
        }
    // Expose resetZoom globally so DOM event handlers can call it from inline/other scopes
    window.resetZoom = resetZoom;
        function renderMinimap(delta) {
            if (myPlayer && myPlayer.alive) {
                mapContext.clearRect(0, 0, mapDisplay.width, mapDisplay.height);

                // RENDER PINGS:
                mapContext.strokeStyle = "#fff";
                mapContext.lineWidth = 4;
                for (var i = 0; i < mapPings.length; ++i) {
                    tmpPing = mapPings[i];
                    tmpPing.update(mapContext, delta);
                }

                // RENDER PLAYERS:
                mapContext.globalAlpha = 1;
                mapContext.fillStyle = "#fff";
                renderCircle((myPlayer.x/config.mapScale)*mapDisplay.width,
                             (myPlayer.y/config.mapScale)*mapDisplay.height, 7, mapContext, true);
                mapContext.fillStyle = "rgba(255,255,255,0.35)";
                if (myPlayer.team && minimapData) {
                    for (var i = 0; i < minimapData.length;) {
                        renderCircle((minimapData[i]/config.mapScale)*mapDisplay.width,
                                     (minimapData[i+1]/config.mapScale)*mapDisplay.height, 7, mapContext, true);
                        i+=2;
                    }
                }

                // DEATH LOCATION:
                if (lastDeath) {
                    mapContext.fillStyle = "#fc5553";
                    mapContext.font = "34px Hammersmith One";
                    mapContext.textBaseline = "middle";
                    mapContext.textAlign = "center";
                    mapContext.fillText("x", (lastDeath.x/config.mapScale)*mapDisplay.width,
                                        (lastDeath.y/config.mapScale)*mapDisplay.height);
                }

                // MAP MARKER:
                if (mapMarker) {
                    mapContext.fillStyle = "#fff";
                    mapContext.font = "34px Hammersmith One";
                    mapContext.textBaseline = "middle";
                    mapContext.textAlign = "center";
                    mapContext.fillText("x", (mapMarker.x/config.mapScale)*mapDisplay.width,
                                        (mapMarker.y/config.mapScale)*mapDisplay.height);
                }
            }
        }

