// SMART PVP FUNCTIONS
// ============================================================

// 1. AUTO INSTA-COUNTER: when enemy can insta you, auto counter
function autoInstaCounter() {
    if (!settings.autoInstaCounter) return;
    if (!nearestEnemy) return;
    if (autoaim) return;
    if (instaKill && instaKill.length > 0) return;

    const dist = UTILS.getDistance(myPlayer.x2, myPlayer.y2, nearestEnemy.x2, nearestEnemy.y2);
    const myPrimaryRange = items.weapons[myPlayer.weapons[0]].range + myPlayer.scale + nearestEnemy.scale;

    if (dist > myPrimaryRange) return;
    if (primaryReload[nearestEnemy.sid] < 1) return;

    const enemyPrimaryDmg = getPlayerInfo(nearestEnemy, "primaryDmg");
    if (!enemyPrimaryDmg) return;

    const isDangerous = enemyPrimaryDmg >= 40;
    const isLowHP = myPlayer.health <= 60;

    if (!isDangerous && !isLowHP) return;
    if (primaryReload[myPlayer.sid] !== 1) return;
    if (!isBoughtHat(7, 0) && !isBoughtHat(40, 0)) return;

    autoaim = true;
    const angle = Math.atan2(nearestEnemy.y2 - myPlayer.y2, nearestEnemy.x2 - myPlayer.x2);

    if (isBoughtHat(40, 0)) hat(40, 0);

    setTimeout(() => {
        selectWeapon(myPlayer.weapons[0]);
        io.send("D", angle);
        sendAtck(1, angle);
        sendAtck(0, angle);
        setTimeout(() => {
            if (isBoughtHat(7, 0)) hat(7, 0);
            autoaim = false;
        }, 90);
    }, 1);
}

// 2. SMART DODGE: move perpendicular when enemy attacks
function smartDodge() {
    if (!settings.smartDodge) return;
    if (!nearestEnemy) return;
    if (autoaim) return;
    if (imTrapped) return;

    const dist = UTILS.getDistance(myPlayer.x2, myPlayer.y2, nearestEnemy.x2, nearestEnemy.y2);
    const myRange = items.weapons[myPlayer.weapons[0]].range + myPlayer.scale + nearestEnemy.scale;

    if (dist > myRange) return;
    if (primaryReload[nearestEnemy.sid] < 1) return;

    const angleToUs = Math.atan2(myPlayer.y2 - nearestEnemy.y2, myPlayer.x2 - nearestEnemy.x2);
    predictMoveAngle = angleToUs + Math.PI / 2;
}

// 3. AUTO BULL ON DAMAGE: instantly switch to bull when taking damage
let lastHealthCheck = 100;
function autoBullOnDamage() {
    if (!settings.autoBullOnDamage) return;
    if (!myPlayer.alive) return;

    const currentHealth = myPlayer.health;
    if (currentHealth < lastHealthCheck && lastHealthCheck - currentHealth > 5) {
        if (isBoughtHat(7, 0) && myPlayer.skinIndex !== 7) {
            hat(7, 0);
        }
    }
    lastHealthCheck = currentHealth;
}

// 4. PREDICTIVE KNOCKBACK: knockback enemy to predicted trap position
function predictiveKnockback() {
    if (!settings.predictiveKnockback) return;
    if (!nearestEnemy) return;
    if (autoaim) return;
    if (primaryReload[myPlayer.sid] !== 1) return;

    const dist = UTILS.getDistance(myPlayer.x2, myPlayer.y2, nearestEnemy.x2, nearestEnemy.y2);
    const myRange = items.weapons[myPlayer.weapons[0]].range + myPlayer.scale;

    if (dist > myRange) return;

    const myTraps = visibleObjects.filter(o =>
        o.id === 15 && o.owner &&
        (o.owner.sid === myPlayer.sid || isAlly(o.owner.sid)) &&
        UTILS.getDistance(nearestEnemy.x2, nearestEnemy.y2, o.x, o.y) <= 120
    );

    if (myTraps.length === 0) return;

    let bestTrap = null;
    let bestScore = -Infinity;

    for (const trap of myTraps) {
        const distToEnemy = UTILS.getDistance(nearestEnemy.x2, nearestEnemy.y2, trap.x, trap.y);
        const angleToTrap = Math.atan2(trap.y - nearestEnemy.y2, trap.x - nearestEnemy.x2);
        const angleToUs = Math.atan2(myPlayer.y2 - nearestEnemy.y2, myPlayer.x2 - nearestEnemy.x2);

        let angleDiff = Math.abs(angleToTrap - angleToUs);
        if (angleDiff > Math.PI) angleDiff = 2 * Math.PI - angleDiff;

        const score = (120 - distToEnemy) + (Math.PI - angleDiff) * 50;
        if (score > bestScore) { bestScore = score; bestTrap = trap; }
    }

    if (!bestTrap || bestScore < 50) return;

    const angle = Math.atan2(nearestEnemy.y2 - myPlayer.y2, nearestEnemy.x2 - myPlayer.x2);
    autoaim = true;

    if (isBoughtHat(6, 0)) hat(6, 0);
    selectWeapon(myPlayer.weapons[0]);
    io.send("D", angle);
    sendAtck(1, angle);
    sendAtck(0, angle);

    setTimeout(() => {
        autoaim = false;
        if (isBoughtHat(40, 0)) hat(40, 0);
    }, 100);
}

// 5. SMART TRAP PRIORITY: smart order for breaking objects
function getSmartBreakPriority() {
    if (!settings.smartTrapPriority) return null;
    if (!nearestEnemy) return null;

    const nearEnemyObjects = visibleObjects.filter(o =>
        o.owner && o.owner.sid !== myPlayer.sid && !isAlly(o.owner.sid) &&
        UTILS.getDistance(nearestEnemy.x2, nearestEnemy.y2, o.x, o.y) <= 60 &&
        UTILS.getDistance(myPlayer.x2, myPlayer.y2, o.x, o.y) <= (items.weapons[myPlayer.weapons[0]].range + myPlayer.scale + o.scale)
    );

    if (nearEnemyObjects.length === 0) return null;

    const scores = nearEnemyObjects.map(o => {
        let score = 0;
        if (o.id === 15) score += 100;
        else if (o.id === 22) score += 80;
        else if (o.id >= 6 && o.id <= 9) score += 60;
        else if (o.id === 18) score += 40;

        const distToEnemy = UTILS.getDistance(nearestEnemy.x2, nearestEnemy.y2, o.x, o.y);
        score += (60 - distToEnemy);

        if (o.id === 15 && nearestEnemy.spikeDamage > 0) score += 50;
        if (canOneHitTrap(o)) score += 30;

        return { object: o, score: score };
    });

    scores.sort((a, b) => b.score - a.score);
    return scores[0].object;
}
