        window.addEventListener('keydown', UTILS.checkTrusted(keyDown));
        function keyUp(event) {
            // Process key releases even if player is dead so held placement keys don't carry over through death.
            var keyNum = event.which||event.keyCode||0; //Aggiunge il listener per i tasti premuti con controllo di sicurezza
            // ENTER toggles chat only if alive and keysActive
            if (keyNum == 13 && myPlayer && myPlayer.alive) {
                toggleChat();
                return;
            }

            // Only process other keys when the UI allows it
            if (!keysActive()) return;

            // Clear stored keys state
            if (keys[keyNum]) keys[keyNum] = 0;


            if (keyNum == 32) { // 'L'
                leftHoldAttack = false;
                leftHoldNoHatFallback = false;
                leftHoldRequireHat = false;
                attackState = 0;
                sendAtckState();
            } else if (keyNum == 81) {
                qPress = true;
            } else if (keyNum == 86) { // 'v'
                vPress = false;
            } else if (keyNum == 72) { // 'h'
                hPress = false;
            } else if (keyNum == 70) { // 'f'
                fPress = false;
            }
        }
        window.addEventListener('keyup',  UTILS.checkTrusted(keyUp));
