        // SETUP GAME:
        var firstSetup = true;
        function setupGame(yourSID) {
            loadingText.style.display = "none";
            menuCardHolder.style.display = "block";
            mainMenu.style.display = "none";
            keys = {};
            myPlayerSID = yourSID;
            attackState = 0;
            inGame = true;
            if (firstSetup) {
                firstSetup = false;
                gameObjects.length = 0;
            }
            try {
                // change document title
                document.title = 'God Laffer';

                // show a single entrance banner animation once per page load
                if (!window._plEntranceShown) {
                    window._plEntranceShown = true;
                    // Use an outer holder to center the banner and an inner card to perform
                    // the scale animation. When translate(...) uses percentage values, the
                    // translation is relative to element size and will move during scaling.
                    // Separating the scaling onto an inner element keeps the centered
                    // position stable while the card scales smoothly.
                    var bannerHolder = document.createElement('div');
                    bannerHolder.id = 'pl_enter_banner';
                    bannerHolder.style.position = 'fixed';
                    bannerHolder.style.left = '50%';
                    bannerHolder.style.top = '18%';
                    bannerHolder.style.transform = 'translate(-50%, -50%)';
                    bannerHolder.style.zIndex = 30000;
                    bannerHolder.style.display = 'flex';
                    bannerHolder.style.alignItems = 'center';
                    bannerHolder.style.justifyContent = 'center';
                    bannerHolder.style.pointerEvents = 'none';
                    bannerHolder.style.opacity = '0';

                    var bannerCard = document.createElement('div');
                    bannerCard.id = 'pl_enter_banner_card';
                    // animate scale on this inner element only
                    bannerCard.style.transform = 'scale(0.8)';
                    bannerCard.style.padding = '18px 28px';
                    bannerCard.style.borderRadius = '14px';
                    bannerCard.style.display = 'flex';
                    bannerCard.style.flexDirection = 'column';
                    bannerCard.style.alignItems = 'center';
                    bannerCard.style.justifyContent = 'center';
                    bannerCard.style.background = 'linear-gradient(135deg, rgba(12,15,20,0.85), rgba(6,10,18,0.7))';
                    bannerCard.style.boxShadow = '0 20px 60px rgba(0,0,0,0.6)';
                    bannerCard.style.border = '1px solid rgba(255,255,255,0.04)';
                    bannerCard.style.backdropFilter = 'blur(8px)';
                    bannerCard.style.pointerEvents = 'auto';

                    var big = document.createElement('div');
                    big.style.fontSize = '34px';
                    big.style.fontWeight = '900';
                    big.style.color = 'white';
                    big.style.letterSpacing = '-1px';
                    big.style.textShadow = '0 6px 30px rgba(80,160,255,0.06)';
                    big.innerText = 'Welcome!';

                    var small = document.createElement('div');
                    small.style.fontSize = '13px';
                    small.style.color = '#bcd8ff';
                    small.style.marginTop = '8px';
                    small.innerText = '';

                    bannerCard.appendChild(big);
                    bannerCard.appendChild(small);
                    bannerHolder.appendChild(bannerCard);
                    document.body.appendChild(bannerHolder);

                    // Use CSS transitions (and rAF) for predictable show/hide behavior
                    bannerHolder.style.transition = 'opacity 360ms cubic-bezier(.2,.8,.2,1)';
                    bannerCard.style.transition = 'transform 360ms cubic-bezier(.2,.8,.2,1)';
                    // Force layout then trigger transitions so they run consistently
                    bannerHolder.getBoundingClientRect();
                    requestAnimationFrame(function(){
                        try{ bannerHolder.style.opacity = '1'; }catch(e){}
                        try{ bannerCard.style.transform = 'scale(1)'; }catch(e){}
                    });

                    // Hide after a delay using transitions
                    setTimeout(function() {
                        try{ bannerCard.style.transform = 'scale(0.9)'; }catch(e){}
                        try{ bannerHolder.style.opacity = '0'; }catch(e){}
                        // remove after transition ends (give a small buffer)
                        setTimeout(function(){ try{ bannerHolder.remove(); }catch(e){} }, 420);
                    }, 4000);
                }
            } catch (e) { console.log('[Mod] setupGame visual error', e); }
        }

