        // KILL OBJECT:
        function killObject(sid) {
            removedObjects.push(sid);
            try{ if(lastAutoBreakSid != null && sid == lastAutoBreakSid) console.log(`[Mod] killObject called for current autoBreak sid=${sid}`); }catch(e){}
            // If the removed object is our autoBreak target, force-stop immediately and
            // clear the stop cooldown so manual movement can resume right away.
            try{
                if(lastAutoBreakSid != null && sid == lastAutoBreakSid){
                    try{ console.log(`[Mod] killObject: autoBreak target removed sid=${sid}`); }catch(e){}
                    // Instead of forcing an unconditional stop, only stop if there's
                    // an enemy spike in the current movement direction.
                    try{
                        // determine current/manual movement angle if any
                        let manualAngleNow = (typeof getMoveDir === 'function' ? getMoveDir() : undefined);
                        if(manualAngleNow === undefined && myPlayer){
                            try{
                                if(typeof predictMoveAngle !== 'undefined' && predictMoveAngle !== null){
                                    manualAngleNow = predictMoveAngle;
                                } else if(myPlayer.xVel !== undefined && myPlayer.yVel !== undefined){
                                    manualAngleNow = Math.atan2(myPlayer.yVel - myPlayer.y2, myPlayer.xVel - myPlayer.x2);
                                }
                            }catch(e){}
                        }

                        let shouldStop = false;
                        if(manualAngleNow !== undefined && manualAngleNow !== null && myPlayer){
                            try{
                                // If player is currently inside a trap, do not autostop.
                                // Trap objects use id == 15 in this codebase.
                                try{
                                    // Only consider being "in a trap" for blocking autostop when the trap
                                    // is an enemy-owned trap (owner exists and is not an ally).
                                    const inEnemyTrap = visibleObjects && visibleObjects.some(o => o && o.id == 15 && o.owner && o.owner.sid != myPlayer.sid && !isAlly(o.owner.sid) && typeof o.x === 'number' && typeof o.y === 'number' && UTILS.getDistance(myPlayer.x2, myPlayer.y2, o.x, o.y) <= (o.scale + (myPlayer.scale || 0)));
                                    if(inEnemyTrap){
                                        // inside an enemy trap -> do not autostop
                                        lastAutoStopPosX = null;
                                        lastAutoStopPosY = null;
                                    } else {
                                        const enemySpikesNow = visibleObjects.filter(object => object.id > 5 && object.id < 10 && object.owner && object.owner.sid != myPlayer.sid && !isAlly(object.owner.sid));
                                        const ANGLE_TOLERANCE = (Math.PI / 4); // 45 degrees
                                        // Hardcoded autostop thresholds
                                        const NEAR_THRESHOLD = 35;
                                        let BRAKE_BUFFER = 60;
                                        try {
                                            if (myPlayer && Array.isArray(myPlayer.weapons) && (myPlayer.weapons[0] === 6 || myPlayer.weapons[0] === 7) && myPlayer.weaponIndex === myPlayer.weapons[0]) {
                                                BRAKE_BUFFER += 10;
                                            }
                                        } catch (e) {}
                                        const DIST_THRESHOLD = NEAR_THRESHOLD + BRAKE_BUFFER;
                                        for(const sp of enemySpikesNow){
                                            if(sp && sp.x !== undefined && sp.y !== undefined){
                                                const dist = UTILS.getDistance(myPlayer.x2, myPlayer.y2, sp.x, sp.y);
                                                if(dist <= DIST_THRESHOLD){
                                                    let dirToSpike = Math.atan2(sp.y - myPlayer.y2, sp.x - myPlayer.x2);
                                                     angleDiff = Math.abs(manualAngleNow - dirToSpike);
                                                    if(angleDiff > Math.PI) angleDiff = 2 * Math.PI - angleDiff;
                                                    if(angleDiff <= ANGLE_TOLERANCE){
                                                        shouldStop = true;
                                                        lastAutoStopPosX = sp.x;
                                                        lastAutoStopPosY = sp.y;
                                                        break;
                                                    }
                                                }
                                            }
                                        }
                                    }
                                }catch(e){}
                            }catch(e){}
                        }

                        if(shouldStop){
                            // If player's current speed is over threshold, skip autostop (let momentum carry through)
                            try{
                                const currentSpeed = getPlayerSpeed();
                                if(currentSpeed > 66){
                                    try{ console.log('[Mod] skipping autostop due to high speed', currentSpeed); }catch(e){}
                                    // clear stop markers so movement continues
                                    lastAutoStopPosX = null;
                                    lastAutoStopPosY = null;
                                    shouldStop = false;
                                }
                            }catch(e){}
                            // Spike still ahead: force a stop (preserve previous safety behavior) РІР‚вЂќ only if shouldStop still true
                            try{ if(shouldStop) { if(settings && settings.autostop_before_collision) stopMovementServerOnly(); } }catch(e){}
                            // Show a visible label so the user knows we autostopped before collision
                            try{
                                if(typeof textManager !== 'undefined' && myPlayer && settings && settings.label_autostop_enabled){
                                    // show slightly above the player using label settings
                                    var _as_size = Number(settings.label_size) || 20;
                                    var _as_speed = Number(settings.label_speed) || 0.12;
                                    var _as_life = Number(settings.label_life) || 600;
                                    var _as_color = settings.label_autostop_color || "#ff5252";
                                    try{ textManager.showText(myPlayer.x2, myPlayer.y2 - (myPlayer.scale || 0) - 30, _as_size, _as_speed, _as_life, "AUTO STOP", _as_color); }catch(e){}
                                }
                            }catch(e){}
                            // Suppress movement sends briefly so the server processes the stop
                            stopMovementTick = (typeof tick !== 'undefined') ? tick + 1 : 1;
                            predictMoveAngle = null;
                        } else {
                            // No spike ahead: clear autostop marker and allow movement now.
                            lastAutoStopPosX = null;
                            lastAutoStopPosY = null;
                            // Clear any stop cooldown so movement sends are honored immediately
                            stopMovementTick = (typeof tick !== 'undefined') ? tick : 0;
                            predictMoveAngle = null;
                            try{
                                const manualAngleNow = (typeof getMoveDir === 'function' ? getMoveDir() : undefined);
                                if(manualAngleNow !== undefined){
                                    try{ io.send("9", manualAngleNow); }catch(e){}
                                }
                            }catch(e){}
                        }

                        autoBreak = false;
                        lastAutoBreakSid = null;
                        lastAutoBreakPosX = null;
                        lastAutoBreakPosY = null;
                    }catch(e){}
                }
            }catch(e){}
            objectManager.disableBySid(sid);
        }

