        // UPDATE LEADERBOARD:
        function updateLeaderboard(data) {
            UTILS.removeAllChildren(leaderboardData);
            var tmpC = 1;
            for (var i = 0; i < data.length; i += 3) {
                (function(i) {
                    UTILS.generateElement({
                        class: "leaderHolder",
                        parent: leaderboardData,
                        children: [
                            UTILS.generateElement({
                                class: "leaderboardItem",
                                style: "color:" + ((data[i] == myPlayerSID) ? "#fff" : "rgba(255,255,255,0.6)"),
                                text: tmpC + ". " + (data[i+1] != "" ? data[i+1] : "unknown")
                            }),
                            UTILS.generateElement({
                                class: "leaderScore",
                                text: UTILS.kFormat(data[i+2]) || "0"
                            })
                        ]
                    });
                })(i);
                tmpC++;
            }
        }

        // UPDATE GAME:
        function updateGame() {
            if (true) {

                // UPDATE DIRECTION:
                /*
                if (player) {
                    if (!lastSent || now - lastSent >= (1000 / config.clientSendRate)) {
                        lastSent = now;
                        let atckDir = getAttackDir();
                        if (lessDir !== atckDir) {
                            lessDir = atckDir;
                            io.send("D", atckDir);
                        }
                        tmpAttackDir = atckDir;
                    }
                }
                */

                // DEATH TEXT:
                if (deathTextScale < 120) {
                    deathTextScale += 0.1 * delta;
                    diedText.style.fontSize = Math.min(Math.round(deathTextScale), 120) + "px";
                }

                // MOVE CAMERA:
                if (myPlayer) {
                    var tmpDist = UTILS.getDistance(camX, camY, myPlayer.x, myPlayer.y);
                    var tmpDir = UTILS.getDirection(myPlayer.x, myPlayer.y, camX, camY);
                    var camSpd = Math.min(tmpDist * 0.01 * delta, tmpDist);
                    if (tmpDist > 0.05) {
                        camX += camSpd * Math.cos(tmpDir);
                        camY += camSpd * Math.sin(tmpDir);
                    } else {
                        camX = myPlayer.x;
                        camY = myPlayer.y;
                    }
                } else {
                    camX = config.mapScale / 2;
                    camY = config.mapScale / 2;
                }

                // INTERPOLATE PLAYERS AND AI:
                var lastTime = now - (1000 / config.serverUpdateRate);
                var tmpDiff;
                for (var i = 0; i < players.length + ais.length; ++i) {
                    tmpObj = players[i]||ais[i-players.length];
                    if (tmpObj && tmpObj.visible) {
                        if (tmpObj.forcePos) {
                            tmpObj.x = tmpObj.x2;
                            tmpObj.y = tmpObj.y2;
                            tmpObj.dir = tmpObj.d2;
                        } else {
                            var total = tmpObj.t2 - tmpObj.t1;
                            var fraction = lastTime - tmpObj.t1;
                            var ratio = (fraction / total);
                            var rate = 170;
                            tmpObj.dt += delta;
                            var tmpRate = Math.min(1.7, tmpObj.dt / rate);
                            var tmpDiff = (tmpObj.x2 - tmpObj.x1);
                            tmpObj.x = tmpObj.x1 + (tmpDiff * tmpRate);
                            tmpDiff = (tmpObj.y2 - tmpObj.y1);
                            tmpObj.y = tmpObj.y1 + (tmpDiff * tmpRate);
                            tmpObj.dir = Math.lerpAngle(tmpObj.d2, tmpObj.d1, Math.min(1.2, ratio));
                        }
                    }
                }

                // RENDER CORDS:
                var xOffset = camX - (maxScreenWidth / 2);
                var yOffset = camY - (maxScreenHeight / 2);

                // RENDER BACKGROUND:
                if (config.snowBiomeTop - yOffset <= 0 && config.mapScale - config.snowBiomeTop - yOffset >= maxScreenHeight) {
                    mainContext.fillStyle = "#b6db66";
                    mainContext.fillRect(0, 0, maxScreenWidth, maxScreenHeight);
                } else if (config.mapScale - config.snowBiomeTop - yOffset <= 0) {
                    mainContext.fillStyle = "#dbc666";
                    mainContext.fillRect(0, 0, maxScreenWidth, maxScreenHeight);
                } else if (config.snowBiomeTop - yOffset >= maxScreenHeight) {
                    mainContext.fillStyle = "#fff";
                    mainContext.fillRect(0, 0, maxScreenWidth, maxScreenHeight);
                } else if (config.snowBiomeTop - yOffset >= 0) {
                    mainContext.fillStyle = "#fff";
                    mainContext.fillRect(0, 0, maxScreenWidth, config.snowBiomeTop - yOffset);
                    mainContext.fillStyle = "#b6db66";
                    mainContext.fillRect(0, config.snowBiomeTop - yOffset, maxScreenWidth,
                                         maxScreenHeight - (config.snowBiomeTop - yOffset));
                } else {
                    mainContext.fillStyle = "#b6db66";
                    mainContext.fillRect(0, 0, maxScreenWidth,
                                         (config.mapScale - config.snowBiomeTop - yOffset));
                    mainContext.fillStyle = "#dbc666";
                    mainContext.fillRect(0, (config.mapScale - config.snowBiomeTop - yOffset), maxScreenWidth,
                                         maxScreenHeight - (config.mapScale - config.snowBiomeTop - yOffset));
                }
// RENDER GRID:
                if(settings.renderGrid){
                mainContext.lineWidth = 4;
                mainContext.strokeStyle = "#000";
                mainContext.globalAlpha = 0.06;
                mainContext.beginPath();
                for (var x = -camX; x < maxScreenWidth; x += maxScreenHeight / 18) {
                    if (x > 0) {
                        mainContext.moveTo(x, 0);
                        mainContext.lineTo(x, maxScreenHeight);
                    }
                }
                for (var y = -camY; y < maxScreenHeight; y += maxScreenHeight / 18) {
                    if (x > 0) {
                        mainContext.moveTo(0, y);
                        mainContext.lineTo(maxScreenWidth, y);
                    }
                }
                mainContext.stroke();
                }

                // RENDER WATER AREAS:
                if (!firstSetup) {
                    waterMult += waterPlus * config.waveSpeed * delta;
                    if (waterMult >= config.waveMax) {
                        waterMult = config.waveMax;
                        waterPlus = -1;
                    } else if (waterMult <= 1) {
                        waterMult = waterPlus = 1;
                    }
                    mainContext.globalAlpha = 1;
                    mainContext.fillStyle = "#dbc666";
                    renderWaterBodies(xOffset, yOffset, mainContext, config.riverPadding);
                    mainContext.fillStyle = "#91b2db";
                    renderWaterBodies(xOffset, yOffset, mainContext, (waterMult - 1) * 250);
                }

                // RENDER BOTTOM LAYER:
                mainContext.globalAlpha = 1;
                mainContext.strokeStyle = outlineColor;
                renderGameObjects(-1, xOffset, yOffset);

                // RENDER PROJECTILES:
                mainContext.globalAlpha = 1;
                mainContext.lineWidth = outlineWidth;
                renderProjectiles(0, xOffset, yOffset);

                // Left-hold sequence using game.tickBase timing similar to E/tank sequences
                if (leftHoldAttack && typeof tick !== 'undefined' && tick >= leftHoldStepTick) {
                    if (leftHoldStep === 0) {
                        // Equip accessory 0 immediately and schedule bull + primary hit using tickBase
                        try {
                            if (typeof leftHoldDebug !== 'undefined' && leftHoldDebug) console.log('[leftHold] Step 1: Equipping acc(0) at tick', tick);
                            acc(0);
                        } catch(e) {}

                        // Schedule bull equip on next tick and primary attack on following tick using game.tickBase
                        try {
                            if (typeof leftHoldDebug !== 'undefined' && leftHoldDebug) console.log('[leftHold] scheduling tickBase sequence');
                            game.tickBase(() => {
                                    try {
                                        if (typeof leftHoldDebug !== 'undefined' && leftHoldDebug) console.log('[leftHold] tickBase 1 running: equipping bull (force) requireHat=', leftHoldRequireHat);
                                        // Only call hat when we require it (user owns it). hat() handles force/retry logic.
                                        if (leftHoldRequireHat) hat(7, true);
                                    } catch(e) { if (typeof leftHoldDebug !== 'undefined' && leftHoldDebug) console.log('[leftHold] tickBase 1 error', e); }

                                    // Schedule attempts to attack, but only after the bull helmet is applied.
                                    // We use bounded retries (few ticks) to wait for the hat to apply and for reload to be ready.
                                    game.tickBase(() => {
                                        try {
                                            if (typeof leftHoldDebug !== 'undefined' && leftHoldDebug) console.log('[leftHold] tickBase 2 scheduling: attempt attack after hat');

                                            const tryAttack = function(retries){
                                                game.tickBase(() => {
                                                    try {
                                                        // Check hat applied (or skip check when user doesn't own the hat)
                                                        if(!leftHoldRequireHat || (myPlayer && myPlayer.skinIndex == 7)){
                                                                    // compute ticks to wait between shots based on weapon speed
                                                                    var ticksToReload = 1;
                                                                    try {
                                                                        var weaponId = myPlayer && myPlayer.weapons ? myPlayer.weapons[0] : null;
                                                                        if(weaponId != null && items && items.weapons && game && game.tickRate){
                                                                            ticksToReload = Math.max(1, Math.ceil(items.weapons[weaponId].speed / game.tickRate));
                                                                        }
                                                                    } catch(e){ ticksToReload = 1; }

                                                                    // Schedule the actual hit 3 ticks after the hat was detected as applied
                                                                    game.tickBase(() => {
                                                                        try {
                                                                            try { selectWeapon(0, false); } catch(e) {}
                                                                            // ensure attack state is set so server recognizes aggressive action
                                                                            try { attackState = 1; sendAtckState(); } catch(e) {}
                                                                            if (primaryReload && primaryReload[myPlayer.sid] == 1) {
                                                                                var atckDir = getAttackDir();
                                                                                try { if (typeof leftHoldDebug !== 'undefined' && leftHoldDebug) console.log('[leftHold] sendAtck(primary)', atckDir); } catch(e) {}
                                                                                sendAtck(0, atckDir);
                                                                                // enforce a cooldown in ticks to avoid sending every tick
                                                                                try { lastLeftAttackTime = (typeof tick !== 'undefined' ? tick : 0) + ticksToReload; } catch(e) { lastLeftAttackTime = (typeof tick !== 'undefined' ? tick : 0) + 1; }
                                                                            } else {
                                                                                if (retries > 0) {
                                                                                    if (typeof leftHoldDebug !== 'undefined' && leftHoldDebug) console.log('[leftHold] primary not reloaded at scheduled hit, retrying... ticks left', retries);
                                                                                    tryAttack(retries - 1);
                                                                                } else {
                                                                                    if (typeof leftHoldDebug !== 'undefined' && leftHoldDebug) console.log('[leftHold] primary not reloaded after retries');
                                                                                }
                                                                            }
                                                                        } catch(e) { if (typeof leftHoldDebug !== 'undefined' && leftHoldDebug) console.log('[leftHold] scheduled hit error', e); }
                                                                    }, 3);
                                                        } else {
                                                            // Hat not applied yet -> retry until retries exhausted
                                                            if (retries > 0) {
                                                                if (typeof leftHoldDebug !== 'undefined' && leftHoldDebug) console.log('[leftHold] hat not applied yet, retrying... ticks left', retries);
                                                                tryAttack(retries - 1);
                                                            } else {
                                                                if (typeof leftHoldDebug !== 'undefined' && leftHoldDebug) console.log('[leftHold] hat not applied after retries РІР‚вЂќ scheduling fallback attack without hat');
                                                                // enable fallback mode so repeat-fire will continue without requiring the hat
                                                                leftHoldNoHatFallback = true;
                                                                // Fallback: schedule an attack even if hat didn't apply (use same 3-tick post-check delay)
                                                                var ticksToReload = 1;
                                                                try {
                                                                    var weaponId = myPlayer && myPlayer.weapons ? myPlayer.weapons[0] : null;
                                                                    if (weaponId != null && items && items.weapons && game && game.tickRate) {
                                                                        ticksToReload = Math.max(1, Math.ceil(items.weapons[weaponId].speed / game.tickRate));
                                                                    }
                                                                } catch(e) { ticksToReload = 1; }

                                                                game.tickBase(() => {
                                                                    try { selectWeapon(0, false); } catch(e) {}
                                                                    try { attackState = 1; sendAtckState(); } catch(e) {}
                                                                    if (primaryReload && primaryReload[myPlayer.sid] == 1) {
                                                                        var atckDir = getAttackDir();
                                                                        try { if (typeof leftHoldDebug !== 'undefined' && leftHoldDebug) console.log('[leftHold] sendAtck(primary) fallback no-hat', atckDir); } catch(e) {}
                                                                        sendAtck(0, atckDir);
                                                                        try { lastLeftAttackTime = (typeof tick !== 'undefined' ? tick : 0) + ticksToReload; } catch(e) { lastLeftAttackTime = (typeof tick !== 'undefined' ? tick : 0) + 1; }
                                                                    } else {
                                                                        if (typeof leftHoldDebug !== 'undefined' && leftHoldDebug) console.log('[leftHold] fallback primary not reloaded');
                                                                    }
                                                                }, 3);
                                                            }
                                                        }
                                                    } catch(e) { if (typeof leftHoldDebug !== 'undefined' && leftHoldDebug) console.log('[leftHold] tryAttack error', e); }
                                                }, 1);
                                            };

                                            // Start with a few retries (e.g., 4 ticks)
                                            tryAttack(4);
                                        } catch(e) { if (typeof leftHoldDebug !== 'undefined' && leftHoldDebug) console.log('[leftHold] tickBase 2 scheduling error', e); }
                                    }, 1);
                            }, 1);
                        } catch(e) { if (typeof leftHoldDebug !== 'undefined' && leftHoldDebug) console.log('[leftHold] scheduling error', e); }

                        // Move state forward so we don't repeatedly schedule while held; after attack scheduling, keep step at 3 (active)
                        leftHoldStep = 3;
                        leftHoldStepTick = tick + 1;
                    }
                }

                // While leftHold active and step 3, continue firing primary whenever reloaded (preserve original firing logic)
                if (leftHoldAttack && myPlayer && myPlayer.alive && leftHoldStep === 3) {
                    try {
                        // Continue firing while left-hold step is active.
                        // If the user owns the bull helmet (leftHoldRequireHat===true), require it be applied
                        // before firing; otherwise allow firing immediately. Also allow firing when fallback mode is active.
                        if (!leftHoldRequireHat || (myPlayer && myPlayer.skinIndex == 7) || leftHoldNoHatFallback) {
                            // compute ticks to wait between shots based on primary weapon speed
                            var ticksToReload = 1;
                            try {
                                var weaponId = myPlayer && myPlayer.weapons ? myPlayer.weapons[0] : null;
                                if (weaponId != null && items && items.weapons && game && game.tickRate) {
                                    ticksToReload = Math.max(1, Math.ceil(items.weapons[weaponId].speed / game.tickRate));
                                }
                            } catch (e) { ticksToReload = 1; }

                            // Ensure lastLeftAttackTime is treated as next-allowed tick
                            if (typeof lastLeftAttackTime === 'undefined' || lastLeftAttackTime === null) lastLeftAttackTime = 0;

                            if (tick >= lastLeftAttackTime) {
                                // only fire when primary reload is ready
                                if (primaryReload && primaryReload[myPlayer.sid] == 1) {
                                    try { selectWeapon(0, false); } catch (e) {}
                                    try {
                                        var atckDir = getAttackDir();
                                        try { if (typeof leftHoldDebug !== 'undefined' && leftHoldDebug) console.log('[leftHold] sendAtck (repeat)', atckDir, 'tick', typeof tick !== 'undefined' ? tick : 'n/a', 'skinIndex', (myPlayer && myPlayer.skinIndex), 'primaryReload', primaryReload && primaryReload[myPlayer.sid]); } catch (e) {}
                                        // ensure attack state is set so server recognizes aggressive action
                                        try { attackState = 1; sendAtckState(); } catch(e) {}
                                        sendAtck(0, atckDir);
                                    } catch (e) {}

                                    // set next allowed attack tick to respect weapon speed
                                    try { lastLeftAttackTime = tick + ticksToReload; } catch (e) { lastLeftAttackTime = tick + 1; }
                                } else {
                                    if (typeof leftHoldDebug !== 'undefined' && leftHoldDebug) console.log('[leftHold] repeat: primary not reloaded, waiting');
                                }
                            }
                        }
                    } catch(e) {}
                } else {
                    // when leftHoldAttack released, restore previously saved equips if any
                    if (!leftHoldAttack && (_savedWeapon !== null || _savedHat !== null || _savedAcc !== null)) {
                        try { if (_savedWeapon !== null) selectWeapon(_savedWeapon, false); } catch(e) {}
                        try { if (_savedHat !== null) hat(_savedHat); } catch(e) {}
                        try { if (_savedAcc !== null) acc(_savedAcc); } catch(e) {}
                        _savedWeapon = _savedHat = _savedAcc = null;
                    }
                }

                // RENDER VELOCITY POSITION
                if(myPlayer && myPlayer.alive){
                    mainContext.globalAlpha = 0.5;

                    mainContext.save();
                    mainContext.translate(myPlayer.xVel - xOffset, myPlayer.yVel - yOffset);

                    mainContext.rotate(myPlayer.dir);
                    renderPlayer(myPlayer, mainContext);
                    mainContext.restore();

                    mainContext.globalAlpha = 1;
                }

                // RENDER PLAYERS:
                renderPlayers(xOffset, yOffset, 0);

                // RENDER AI:
                mainContext.globalAlpha = 1;
                for (var i = 0; i < ais.length; ++i) {
                    tmpObj = ais[i];
                    if (tmpObj.active && tmpObj.visible) {
                        tmpObj.animate(delta);
                        mainContext.save();
                        mainContext.translate(tmpObj.x - xOffset, tmpObj.y - yOffset);
                        mainContext.rotate(tmpObj.dir+tmpObj.dirPlus-(Math.PI/2));
                        renderAI(tmpObj, mainContext);
                        mainContext.restore();
                    }
                }

                // RENDER GAME OBJECTS (LAYERED):
                renderGameObjects(0, xOffset, yOffset);
                renderProjectiles(1, xOffset, yOffset);
                renderGameObjects(1, xOffset, yOffset);
                renderPlayers(xOffset, yOffset, 1);
                renderGameObjects(2, xOffset, yOffset);
                renderGameObjects(3, xOffset, yOffset);

                // MAP BOUNDARIES:
                mainContext.fillStyle = "#000";
                mainContext.globalAlpha = 0.09;
                if (xOffset <= 0) {
                    mainContext.fillRect(0, 0, -xOffset, maxScreenHeight);
                } if (config.mapScale - xOffset <= maxScreenWidth) {
                    var tmpY = Math.max(0, -yOffset);
                    mainContext.fillRect(config.mapScale - xOffset, tmpY, maxScreenWidth - (config.mapScale - xOffset), maxScreenHeight - tmpY);
                } if (yOffset <= 0) {
                    mainContext.fillRect(-xOffset, 0, maxScreenWidth + xOffset, -yOffset);
                } if (config.mapScale - yOffset <= maxScreenHeight) {
                    var tmpX = Math.max(0, -xOffset);
                    var tmpMin = 0;
                    if (config.mapScale - xOffset <= maxScreenWidth)
                        tmpMin = maxScreenWidth - (config.mapScale - xOffset);
                    mainContext.fillRect(tmpX, config.mapScale - yOffset,
                                         (maxScreenWidth - tmpX) - tmpMin, maxScreenHeight - (config.mapScale - yOffset));
                }

                renderEnemyTraps(xOffset, yOffset);
                for(let object of predictObjects){
                    mainContext.globalAlpha = .6;

                    mainContext.save();
                    mainContext.translate(object.x - xOffset, object.y - yOffset);

                    let image = getItemSprite({id: object.id, name: object.name, scale: object.scale, prediction: true, preplace: object.preplace});
                    mainContext.drawImage(image, -(image.width / 2), -(image.height / 2));

                    mainContext.rotate(object.angle);
                    mainContext.restore();
                }

                for(let i in visibleObjects){
                    let object = visibleObjects[i];

                    if(UTILS.getDistance(myPlayer.x, myPlayer.y, object.x, object.y) < 300 && object.isItem){
                        mainContext.globalAlpha = 1;
                        mainContext.lineCap = "round";

                        mainContext.strokeStyle = darkOutlineColor;
                        mainContext.lineWidth = 12.5;

                        mainContext.beginPath();
                        mainContext.arc(object.x - xOffset, object.y - yOffset, object.id > 5 && object.id < 10 ? 30 : 20, 0, object.health * (Math.PI * 2 / object.maxHealth))
                        mainContext.stroke();


const time = Date.now() * 0.003;
const pulse = (Math.sin(time) + 1) / 2;
const baseRed = [178, 42, 42];
const lightRed = [240, 119, 119];
const r = Math.round(baseRed[0] + (lightRed[0] - baseRed[0]) * pulse);
const g = Math.round(baseRed[1] + (lightRed[1] - baseRed[1]) * pulse);
const b = Math.round(baseRed[2] + (lightRed[2] - baseRed[2]) * pulse);
const glowRed = `rgb(${r}, ${g}, ${b})`;
mainContext.strokeStyle =
 object.owner.sid == myPlayer.sid
        ? "#e9b3e9"
        : isAlly(object.owner.sid)
        ? "#518ecc"
        : glowRed;
            mainContext.lineWidth = 5;
                        mainContext.beginPath();
                        mainContext.arc(object.x - xOffset, object.y - yOffset, object.id > 5 && object.id < 10 ? 30 : 20, 0, object.health * (Math.PI * 2 / object.maxHealth))
                        mainContext.stroke();
                    }
                }

                // RENDER DAY/NIGHT TIME:
                mainContext.globalAlpha = 1;
                mainContext.fillStyle = "rgba(0, 0, 40, 0.45)";
                mainContext.fillRect(0, 0, maxScreenWidth, maxScreenHeight);
                // On-screen indicator for active auto-trap-tick
                try {
                    const tickActive =  autoTrapTick;
                    if (tickActive) {
                        const boxW = 220;
                        const boxH = 28;
                        const pad = 12;
                        const x = Math.max(10, maxScreenWidth - boxW - pad);
                        const y = 10;
                        mainContext.save();
                        mainContext.globalAlpha = 0.95;
                        mainContext.fillStyle = "rgba(40, 40, 40, 0.85)";
                        // rounded background
                        if (typeof mainContext.roundRect === 'function') mainContext.roundRect(x, y, boxW, boxH, 6);
                        else mainContext.fillRect(x, y, boxW, boxH);
                        mainContext.fill();
                        mainContext.fillStyle = `rgb(200,220,80)`;
                        mainContext.font = "16px Hammersmith One";
                        mainContext.textBaseline = "middle";
                        mainContext.textAlign = "left";
                        mainContext.fillText("AutoTrap Tick ACTIVE", x + 12, y + boxH / 2);
                        mainContext.restore();
                    }
                } catch (e) {}

                // RENDER PLAYER AND AI UI / PLAYERINFOS:
                mainContext.strokeStyle = darkOutlineColor;
                for (var i = 0; i < players.length + ais.length; ++i) {
                    tmpObj = players[i]||ais[i-players.length];
                    if (tmpObj.visible) {

                        // NAME AND HEALTH:
                        if (tmpObj.skinIndex != 10 || (tmpObj==myPlayer) || (tmpObj.team && tmpObj.team==myPlayer.team)) {
                            var tmpText = (tmpObj.team ? `[${tmpObj.team}] ` : ``) + (tmpObj.name) ;
                            if (tmpText != "") {
                                mainContext.font = (tmpObj.nameScale||30) + "px Hammersmith One";
                                mainContext.fillStyle = "#ffffffff";
                                mainContext.textBaseline = "middle";
                                mainContext.textAlign = "center";
                                mainContext.lineWidth = (tmpObj.nameScale?11:8);
                                mainContext.lineJoin = "round";
                                mainContext.strokeText(tmpText, tmpObj.x - xOffset, (tmpObj.y - yOffset - tmpObj.scale) - config.nameY);
                                if (tmpObj.sid && tmpObj.isPlayer) {
                                    mainContext.fillText(tmpObj.sid, tmpObj.x - xOffset, (tmpObj.y - yOffset - tmpObj.scale) - config.nameY + 67);
                                }
                                mainContext.fillText(tmpText, tmpObj.x - xOffset, (tmpObj.y - yOffset - tmpObj.scale) - config.nameY);
                                if (tmpObj.isLeader && iconSprites["crown"].isLoaded) {
                                    var tmpS = config.crownIconScale;
                                    var tmpX = tmpObj.x - xOffset - (tmpS/2) - (mainContext.measureText(tmpText).width / 2) - config.crownPad;
                                    mainContext.drawImage(iconSprites["crown"], tmpX, (tmpObj.y - yOffset - tmpObj.scale)
                                                          - config.nameY - (tmpS/2) - 5, tmpS, tmpS);
                                } if (tmpObj.iconIndex == 1 && iconSprites["skull"].isLoaded) {
                                    var tmpS = config.crownIconScale;
                                    var tmpX = tmpObj.x - xOffset - (tmpS/2) + (mainContext.measureText(tmpText).width / 2) + config.crownPad;
                                    mainContext.drawImage(iconSprites["skull"], tmpX, (tmpObj.y - yOffset - tmpObj.scale)
                                                          - config.nameY - (tmpS/2) - 5, tmpS, tmpS);
                                }
                            }

                                                // SHAME COUNT:
                     mainContext.globalAlpha = 1;
    mainContext.font = "20px Hammersmith One";
    mainContext.fillStyle = "#ffffff";
    mainContext.strokeStyle = "#000000";
    mainContext.textBaseline = "middle";
    mainContext.textAlign = "center";
    mainContext.lineWidth = 4;
    mainContext.lineJoin = "round";

    let hpText = tmpObj.health + "/" + tmpObj.maxHealth;
    let posXLeft = tmpObj.x - xOffset - 28;
    let posY = tmpObj.y - yOffset + tmpObj.scale + config.nameY + 40;

    mainContext.strokeText(hpText, posXLeft, posY);
    mainContext.fillText(hpText, posXLeft, posY);

    let shameText = (tmpObj.shameCount || 0) + "/8";
    let posXRight = tmpObj.x - xOffset + 35;

    mainContext.strokeText(shameText, posXRight, posY);
    mainContext.fillText(shameText, posXRight, posY);


                            if(tmpObj.health > 0){
                                // HEALTH HOLDER:
                                var tmpWidth = config.healthBarWidth;
                                mainContext.fillStyle = darkOutlineColor;
                                mainContext.roundRect(tmpObj.x - xOffset - config.healthBarWidth - config.healthBarPad,
                                                      (tmpObj.y - yOffset + tmpObj.scale) + config.nameY, (config.healthBarWidth * 2) +
                                                      (config.healthBarPad * 2), 17, 8);
                                mainContext.fill();

                                // HEALTH BAR:
                                mainContext.fillStyle = (tmpObj==myPlayer||(tmpObj.team&&tmpObj.team==myPlayer.team))?"#9bd362ff":"#ad2727ff";
                                mainContext.roundRect(tmpObj.x - xOffset - config.healthBarWidth,
                                                      (tmpObj.y - yOffset + tmpObj.scale) + config.nameY + config.healthBarPad,
                                                      ((config.healthBarWidth * 2) * (tmpObj.health / tmpObj.maxHealth)), 17 - config.healthBarPad * 2, 7);
                                mainContext.fill();
                            }
                        }
                    }
                }



                // RENDER ANIM TEXTS:
                textManager.update(delta, mainContext, xOffset, yOffset);

                // RENDER CHAT MESSAGES:
                for (var i = 0; i < players.length; ++i) {
                    tmpObj = players[i];
                    if (tmpObj.visible && tmpObj.chatCountdown > 0) {
                        tmpObj.chatCountdown -= delta;
                        if (tmpObj.chatCountdown <= 0)
                            tmpObj.chatCountdown = 0;
                        mainContext.font = "32px Hammersmith One";
                        var tmpSize = mainContext.measureText(tmpObj.chatMessage);
                        mainContext.textBaseline = "middle";
                        mainContext.textAlign = "center";
                        var tmpX = tmpObj.x - xOffset;
                        var tmpY = tmpObj.y - tmpObj.scale - yOffset - 90;
                        var tmpH = 47;
                        var tmpW = tmpSize.width + 17;
                        mainContext.fillStyle = "rgba(0,0,0,0.2)";
                        mainContext.roundRect(tmpX-tmpW/2, tmpY-tmpH/2, tmpW, tmpH, 6);
                        mainContext.fill();
                        mainContext.fillStyle = "#fff";
                        mainContext.fillText(tmpObj.chatMessage, tmpX, tmpY);
                    }
                }
            }

            // RENDER MINIMAP:
            renderMinimap(delta);

            // RENDER CONTROLS:
            if (controllingTouch.id !== -1) {
                renderControl(
                    controllingTouch.startX, controllingTouch.startY,
                    controllingTouch.currentX, controllingTouch.currentY
                );
            }
            if (attackingTouch.id !== -1) {
                renderControl(
                    attackingTouch.startX, attackingTouch.startY,
                    attackingTouch.currentX, attackingTouch.currentY
                );
            }
        }

        function renderEnemyTraps(xOffset, yOffset){
            for(let i in predictEnemyTraps){
                let object = predictEnemyTraps[i];

                mainContext.save();
                mainContext.translate(object.x - xOffset, object.y - yOffset);
                let image = getItemSprite({id: object.id, name: items.list[object.id].name, scale: 40, predictEnemyTrap: true});
                mainContext.globalAlpha = .6;
                mainContext.drawImage(image, -(image.width / 2), -(image.height / 2));
                mainContext.restore();
            }
        }

        // RENDER CONTROL:
        function renderControl(startX, startY, currentX, currentY) {
            mainContext.save();
            mainContext.setTransform(1, 0, 0, 1, 0, 0);
            // mainContext.resetTransform();
            mainContext.scale(pixelDensity, pixelDensity);
            var controlRadius = 50;
            mainContext.beginPath();
            mainContext.arc(startX, startY, controlRadius, 0, Math.PI * 2, false);
            mainContext.closePath();
            mainContext.fillStyle = "rgba(255, 255, 255, 0.3)";
            mainContext.fill();
            var offsetX = currentX - startX;
            var offsetY = currentY - startY;
            var mag = Math.sqrt(Math.pow(offsetX, 2) + Math.pow(offsetY, 2));
            var divisor = mag > controlRadius ? (mag / controlRadius) : 1;
            offsetX /= divisor;
            offsetY /= divisor;
            mainContext.beginPath();
            mainContext.arc(startX + offsetX, startY + offsetY, controlRadius * 0.5, 0, Math.PI * 2, false);
            mainContext.closePath();
            mainContext.fillStyle = "white";
            mainContext.fill();
            mainContext.restore();
        }

        // RENDER PROJECTILES:
        function renderProjectiles(layer, xOffset, yOffset) {
            for (var i = 0; i < projectiles.length; ++i) {
                tmpObj = projectiles[i];
                if (tmpObj.active && tmpObj.layer == layer) {
                    tmpObj.update(delta);
                    if (tmpObj.active && isOnScreen(tmpObj.x-xOffset, tmpObj.y-yOffset, tmpObj.scale)) {
                        mainContext.save();
                        mainContext.translate(tmpObj.x - xOffset, tmpObj.y - yOffset);
                        mainContext.rotate(tmpObj.dir);
                        renderProjectile(0, 0, tmpObj, mainContext, 1);
                        mainContext.restore();
                    }
                }
            }
        }

        // RENDER PROJECTILE:
        var projectileSprites = {};
        function renderProjectile(x, y, obj, ctxt, debug) {
            if (obj.src) {
                var tmpSrc = items.projectiles[obj.indx].src;
                var tmpSprite = projectileSprites[tmpSrc];
                if (!tmpSprite) {
                    tmpSprite = new Image();
                    tmpSprite.onload = function() {
                        this.isLoaded = true;
                    }
                    tmpSprite.src = ".././img/weapons/" + tmpSrc + ".png";
                    projectileSprites[tmpSrc] = tmpSprite;
                }
                if (tmpSprite.isLoaded)
                    ctxt.drawImage(tmpSprite, x - (obj.scale / 2), y - (obj.scale / 2), obj.scale, obj.scale);
            } else if (obj.indx == 1) {
                ctxt.fillStyle = "#939393";
                renderCircle(x, y, obj.scale, ctxt);
            }
        }

        // RENDER WATER BODIES:
        function renderWaterBodies(xOffset, yOffset, ctxt, padding) {
            // MIDDLE RIVER:
            var tmpW = config.riverWidth + padding;
            var tmpY = (config.mapScale / 2) - yOffset - (tmpW / 2);
            if (tmpY < maxScreenHeight && tmpY + tmpW > 0) {
                ctxt.fillRect(0, tmpY, maxScreenWidth, tmpW);
            }
        }

        // RENDER GAME OBJECTS:
        function renderGameObjects(layer, xOffset, yOffset) {
            var tmpSprite, tmpX, tmpY;
            for (var i = 0; i < gameObjects.length; ++i) {
                tmpObj = gameObjects[i];
                if (tmpObj.active) {
                    tmpX = tmpObj.x + tmpObj.xWiggle - xOffset;
                    tmpY = tmpObj.y + tmpObj.yWiggle - yOffset;
                    if (layer == 0) {
                        tmpObj.update(delta);
                    }
                    if (tmpObj.layer == layer && isOnScreen(tmpX, tmpY, tmpObj.scale + (tmpObj.blocker||0))) {
                        mainContext.globalAlpha = tmpObj.hideFromEnemy?0.6:1;
                        if(tmpObj.isItem){
                            tmpSprite = getItemSprite(tmpObj);

                            mainContext.save();
                            mainContext.translate(tmpX, tmpY);
                            mainContext.rotate(tmpObj.dir);
                            mainContext.drawImage(tmpSprite, -(tmpSprite.width / 2), -(tmpSprite.height / 2));

                            if(tmpObj.blocker){
                                mainContext.strokeStyle = "#db6e6e";
                                mainContext.globalAlpha = 0.3;
                                mainContext.lineWidth = 6;
                                renderCircle(0, 0, tmpObj.blocker, mainContext, false, true);
                            }

                            mainContext.restore();
                            // Draw red threshold circle for spike detection (visual debug for autostop)
                            try {
                                if (settings && settings.visual_spike_overlay && tmpObj.name && (tmpObj.name.indexOf('spike') !== -1 || tmpObj.name.indexOf('spikes') !== -1)) {
                                    const screenX = tmpX;
                                    const screenY = tmpY;
                                    // Hardcoded autostop visual radius (NEAR_THRESHOLD + BRAKE_BUFFER)
                                    const stopDist = 40 + 50;
                                    mainContext.save();
                                    mainContext.beginPath();
                                    mainContext.strokeStyle = 'rgba(255,0,0,0.6)';
                                    mainContext.lineWidth = 2;
                                    mainContext.arc(screenX, screenY, tmpObj.scale + stopDist, 0, Math.PI * 2);
                                    mainContext.stroke();
                                    mainContext.restore();
                                }
                            } catch (e) {}
                            // Draw small ownership/type center-dot (non-invasive visual aid)
                            try {
                                const name = (tmpObj.name || '').toLowerCase();
                                const isSpike = name.indexOf('spike') !== -1;
                                const isTrap = name.indexOf('trap') !== -1;
                                const isTurret = name.indexOf('turret') !== -1;
                                const isMill = name.indexOf('mill') !== -1 || name.indexOf('windmill') !== -1 || name.indexOf('power mill') !== -1;

                                if (isSpike || isTrap || isTurret || isMill) {
                                    const ownerSid = (tmpObj.owner && tmpObj.owner.sid) ? tmpObj.owner.sid : null;
                                    const ownedByMe = (ownerSid !== null && myPlayer && ownerSid == myPlayer.sid);
                                    const ownedByAlly = (ownerSid !== null && !ownedByMe && !!isAlly(ownerSid));

                                    // choose color by (enemy vs ally/my) and type
                                    let color = '#ffffff';
                                    if (ownedByMe || ownedByAlly) {
                                        if (isSpike) color = '#2ecc40'; // green
                                        else if (isTrap) color = '#71aad6'; // blue
                                        else if (isMill) color = '#8ed6ff'; // light blue
                                        else if (isTurret) color = '#ff8c00'; // orange
                                    } else {
                                        if (isSpike) color = '#ff3333'; // red
                                        else if (isTrap) color = '#9b59b6'; // purple
                                        else if (isMill) color = '#8b5a2b'; // brown
                                        else if (isTurret) color = '#000000'; // black
                                    }

                                    const radius = Math.max(3, Math.round((tmpObj.scale || 20) * 0.12));
                                    mainContext.save();
                                    mainContext.beginPath();
                                    mainContext.fillStyle = color;
                                    mainContext.arc(tmpX, tmpY, radius, 0, Math.PI * 2);
                                    mainContext.fill();
                                    mainContext.restore();
                                }
                            } catch (e) {}
                        } else {
                            tmpSprite = getResSprite(tmpObj);
                            mainContext.drawImage(tmpSprite, tmpX - (tmpSprite.width / 2), tmpY - (tmpSprite.height / 2));
                            // Draw red threshold circle for spike detection on resource-drawn spikes
                            try {
                                if (settings && settings.visual_spike_overlay && tmpObj.name && (tmpObj.name.indexOf('spike') !== -1 || tmpObj.name.indexOf('spikes') !== -1)) {
                                    const screenX = tmpX;
                                    const screenY = tmpY;
                                    // Hardcoded autostop visual radius (NEAR_THRESHOLD + BRAKE_BUFFER)
                                    const stopDist = 40 + 50;
                                    mainContext.save();
                                    mainContext.beginPath();
                                    mainContext.strokeStyle = 'rgba(255,0,0,0.6)';
                                    mainContext.lineWidth = 2;
                                    mainContext.arc(screenX, screenY, tmpObj.scale + stopDist, 0, Math.PI * 2);
                                    mainContext.stroke();
                                    mainContext.restore();
                                }
                            } catch (e) {}
                            // Draw small ownership/type center-dot for resource-drawn objects
                            try {
                                const name = (tmpObj.name || '').toLowerCase();
                                const isSpike = name.indexOf('spike') !== -1;
                                const isTrap = name.indexOf('trap') !== -1;
                                const isTurret = name.indexOf('turret') !== -1;
                                const isMill = name.indexOf('mill') !== -1 || name.indexOf('windmill') !== -1 || name.indexOf('power mill') !== -1;

                                if (isSpike || isTrap || isTurret || isMill) {
                                    const ownerSid = (tmpObj.owner && tmpObj.owner.sid) ? tmpObj.owner.sid : null;
                                    const ownedByMe = (ownerSid !== null && myPlayer && ownerSid == myPlayer.sid);
                                    const ownedByAlly = (ownerSid !== null && !ownedByMe && !!isAlly(ownerSid));

                                    let color = '#ffffff';
                                    if (ownedByMe || ownedByAlly) {
                                        if (isSpike) color = '#2ecc40';
                                        else if (isTrap) color = '#71aad6';
                                        else if (isMill) color = '#8ed6ff';
                                        else if (isTurret) color = '#ff8c00';
                                    } else {
                                        if (isSpike) color = '#ff3333';
                                        else if (isTrap) color = '#9b59b6';
                                        else if (isMill) color = '#8b5a2b';
                                        else if (isTurret) color = '#000000';
                                    }

                                    const radius = Math.max(3, Math.round((tmpObj.scale || 20) * 0.12));
                                    mainContext.save();
                                    mainContext.beginPath();
                                    mainContext.fillStyle = color;
                                    mainContext.arc(tmpX, tmpY, radius, 0, Math.PI * 2);
                                    mainContext.fill();
                                    mainContext.restore();
                                }
                            } catch (e) {}
                        }
                    }
                }
            }
        }

        // GATHER ANIMATION:
        function gatherAnimation(sid, isObjectHit, weapon) {
            tmpObj = findPlayerBySID(sid);
            if (tmpObj) {
                hits.push({player: tmpObj, isObjectHit: isObjectHit, weapon: weapon});

                if(isObjectHit){
                    objectHits.push({objects: damageObjects, player: tmpObj, weapon: weapon});
                    damageObjects = [];
                }

                tmpObj.startAnim(isObjectHit, weapon);
            }
        }

        // RENDER PLAYERS:
        function renderPlayers(xOffset, yOffset, zIndex) {
            mainContext.globalAlpha = 1;
            for (var i = 0; i < players.length; ++i) {
                tmpObj = players[i];
                if (tmpObj.zIndex == zIndex) {
                    tmpObj.animate(delta);
                    if (tmpObj.visible) {
                        tmpObj.skinRot += (0.002 * delta);
                        tmpDir = ((tmpObj == myPlayer) ? getAttackDir() : tmpObj.dir) + tmpObj.dirPlus;
                        mainContext.save();
                        mainContext.translate(tmpObj.x - xOffset, tmpObj.y - yOffset);
                        // RENDER PLAYER:
                        mainContext.rotate(tmpDir);
                        renderPlayer(tmpObj, mainContext);
                        mainContext.restore();
                    }
                }
            }
            // Draw auto-velocity debug rings on the top player pass so they are visible
            try{
                if(zIndex === 1 && autoVelocityTickToggled && nearestEnemy && myPlayer && myPlayer.alive){
                    if(settings && settings.visual_veltick_radius){
                    let minimumOTRange = ((1.5 * (1000/9)) + 35);
                    let maximumOTRange = ((1.5 * (1000/9)) + 80);
                    const screenX = nearestEnemy.x2 - xOffset;
                    const screenY = nearestEnemy.y2 - yOffset;
                    mainContext.save();
                    mainContext.beginPath();
                    mainContext.strokeStyle = 'rgba(107,111,224,0.36)';
                    mainContext.lineWidth = 3;
                    mainContext.arc(screenX, screenY, minimumOTRange, 0, Math.PI * 2);
                    mainContext.stroke();

                    mainContext.beginPath();
                    mainContext.strokeStyle = 'rgba(107,111,224,0.18)';
                    mainContext.lineWidth = 2;
                    mainContext.arc(screenX, screenY, maximumOTRange, 0, Math.PI * 2);
                    mainContext.stroke();
                    // Extra debug inner ring (minimumOTRange - 30)
                    try{
                        const innerRadius = Math.max(1, minimumOTRange - 10);
                        mainContext.beginPath();
                        mainContext.strokeStyle = 'rgba(107,111,224,0.28)';
                        mainContext.lineWidth = 1.5;
                        mainContext.arc(screenX, screenY, innerRadius, 0, Math.PI * 2);
                        mainContext.stroke();
                    }catch(e){}

                    // Extra debug outer ring (maximumOTRange + 30)
                    try{
                        const outerRadius = maximumOTRange + 10;
                        mainContext.beginPath();
                        mainContext.strokeStyle = 'rgba(107,111,224,0.12)';
                        mainContext.lineWidth = 1.5;
                        mainContext.arc(screenX, screenY, outerRadius, 0, Math.PI * 2);
                        mainContext.stroke();
                    }catch(e){}

                    mainContext.restore();
            }
        }
                // Draw autoplacer scan visuals
                try{
                    if(zIndex === 1){
                        const now = Date.now();
                        // Autoplacer scan visuals
                        try{
                            if(typeof getAutoplacerDebug === 'function' && getAutoplacerDebug()){
                                mainContext.save();
                                for(let i = scanVisuals.length - 1; i >= 0; --i){
                                    const v = scanVisuals[i];
                                    if(now - v.t > 1200){ scanVisuals.splice(i, 1); continue; }
                                    const sx = v.x - xOffset;
                                    const sy = v.y - yOffset;
                                    mainContext.beginPath();
                                    mainContext.strokeStyle = v.placeable ? 'rgba(80,200,120,0.45)' : 'rgba(255,80,80,0.25)';
                                    mainContext.lineWidth = v.perfect ? 2.5 : 1.2;
                                    mainContext.moveTo(myPlayer.x2 - xOffset, myPlayer.y2 - yOffset);
                                    mainContext.lineTo(sx, sy);
                                    mainContext.stroke();
                                    mainContext.beginPath();
                                    mainContext.fillStyle = v.placeable ? 'rgba(80,200,120,0.9)' : 'rgba(255,80,80,0.9)';
                                    mainContext.arc(sx, sy, v.perfect ? 4 : 2.5, 0, Math.PI * 2);
                                    mainContext.fill();
                                }
                                mainContext.restore();
                            }
                        }catch(e){}

                        // Preplacer visuals (rays and spikes)
                        try{
                            if(typeof getPreplacerDebug === 'function' && getPreplacerDebug()){
                                mainContext.save();
                                for(let i = preplacerVisuals.length - 1; i >= 0; --i){
                                    const v = preplacerVisuals[i];
                                    if(now - v.t > 1200){ preplacerVisuals.splice(i, 1); continue; }
                                    const sx = v.x - xOffset;
                                    const sy = v.y - yOffset;
                                    // draw ray
                                    mainContext.beginPath();
                                    mainContext.strokeStyle = v.hit ? 'rgba(255,180,80,0.95)' : 'rgba(180,180,255,0.6)';
                                    mainContext.lineWidth = v.hit ? 3 : 1.4;
                                    mainContext.moveTo(v.fromX - xOffset, v.fromY - yOffset);
                                    mainContext.lineTo(v.toX - xOffset, v.toY - yOffset);
                                    mainContext.stroke();
                                    // highlight spikes hit
                                    if(v.spikes && v.spikes.length){
                                        for(const s of v.spikes){
                                            mainContext.beginPath();
                                            mainContext.strokeStyle = 'rgba(255,80,80,0.95)';
                                            mainContext.lineWidth = 2;
                                            mainContext.arc(s.x - xOffset, s.y - yOffset, Math.max(6, s.scale), 0, Math.PI * 2);
                                            mainContext.stroke();
                                        }
                                    }
                                }
                                mainContext.restore();
                            }
                        }catch(e){}
                    }
                }catch(e){}
                // Render any queued vel-tick labels so they appear during the player pass
                try{
                    if(typeof velTickLabels !== 'undefined' && velTickLabels.length){
                        while(velTickLabels.length){
                            const lbl = velTickLabels.shift();
                            try{
                                if(typeof textManager !== 'undefined'){
                                    textManager.showText(lbl.x, lbl.y, lbl.size, lbl.speed, lbl.life, lbl.text, lbl.color);
                                } else {
                                    // Canvas fallback: draw text directly
                                    mainContext.save();
                                    mainContext.fillStyle = lbl.color || '#fff';
                                    mainContext.font = (lbl.size || 15) + 'px Arial';
                                    mainContext.textAlign = 'center';
                                    mainContext.fillText(lbl.text, lbl.x - xOffset, lbl.y - yOffset);
                                    mainContext.restore();
                                }
                            }catch(e){}
                        }
                    }
                }catch(e){}
            }catch(e){}
        }

        // RENDER PLAYER:
        function renderPlayer(obj, ctxt) {
            ctxt = ctxt || mainContext;
            ctxt.lineWidth = outlineWidth;
            ctxt.lineJoin = "miter";
            var handAngle = (Math.PI / 4) * (items.weapons[obj.weaponIndex].armS||1);
            var oHandAngle = (obj.buildIndex < 0)?(items.weapons[obj.weaponIndex].hndS||1):1;
            var oHandDist = (obj.buildIndex < 0)?(items.weapons[obj.weaponIndex].hndD||1):1;

            // TAIL/CAPE:
            if (obj.tailIndex > 0) {
                renderTail(obj.tailIndex, ctxt, obj);
            }

            // WEAPON BELLOW HANDS:
            if (obj.buildIndex < 0 && !items.weapons[obj.weaponIndex].aboveHand) {
                renderTool(items.weapons[obj.weaponIndex], config.weaponVariants[obj.weaponVariant].src, obj.scale, 0, ctxt);
                if (items.weapons[obj.weaponIndex].projectile != undefined && !items.weapons[obj.weaponIndex].hideProjectile) {
                    renderProjectile(obj.scale, 0,
                                     items.projectiles[items.weapons[obj.weaponIndex].projectile], mainContext);
                }
            }

            // HANDS:
            ctxt.fillStyle = config.skinColors[obj.skinColor];
            renderCircle(obj.scale * Math.cos(handAngle), (obj.scale * Math.sin(handAngle)), 14);
            renderCircle((obj.scale * oHandDist) * Math.cos(-handAngle * oHandAngle),
                         (obj.scale * oHandDist) * Math.sin(-handAngle * oHandAngle), 14);

            // WEAPON ABOVE HANDS:
            if (obj.buildIndex < 0 && items.weapons[obj.weaponIndex].aboveHand) {
                renderTool(items.weapons[obj.weaponIndex], config.weaponVariants[obj.weaponVariant].src, obj.scale, 0, ctxt);
                if (items.weapons[obj.weaponIndex].projectile != undefined && !items.weapons[obj.weaponIndex].hideProjectile) {
                    renderProjectile(obj.scale, 0,
                                     items.projectiles[items.weapons[obj.weaponIndex].projectile], mainContext);
                }
            }

            // BUILD ITEM:
            if (obj.buildIndex >= 0) {
                var tmpSprite = getItemSprite(items.list[obj.buildIndex]);
                ctxt.drawImage(tmpSprite, obj.scale - items.list[obj.buildIndex].holdOffset, -tmpSprite.width / 2);
            }

            // BODY:
            renderCircle(0, 0, obj.scale, ctxt);

            // SKIN:
            if (obj.skinIndex > 0) {
                ctxt.rotate(Math.PI/2);
                renderSkin(obj.skinIndex, ctxt, null, obj);
            }
        }

        // RENDER SKINS:
        var skinSprites = {};
        var skinPointers = {};
        var tmpSkin;
        function renderSkin(index, ctxt, parentSkin, owner) {
            tmpSkin = skinSprites[index];
            if (!tmpSkin) {
                var tmpImage = new Image();
                tmpImage.onload = function() {
                    this.isLoaded = true;
                    this.onload = null;
                };
                tmpImage.src = ".././img/hats/hat_" + index + ".png";
                skinSprites[index] = tmpImage;
                tmpSkin = tmpImage;
            }
            var tmpObj = parentSkin||skinPointers[index];
            if (!tmpObj) {
                for (var i = 0; i < hats.length; ++i) {
                    if (hats[i].id == index) {
                        tmpObj = hats[i];
                        break;
                    }
                }
                skinPointers[index] = tmpObj;
            }
            if (tmpSkin.isLoaded)
                ctxt.drawImage(tmpSkin, -tmpObj.scale/2, -tmpObj.scale/2, tmpObj.scale, tmpObj.scale);
            if (!parentSkin && tmpObj.topSprite) {
                ctxt.save();
                ctxt.rotate(owner.skinRot);
                renderSkin(index + "_top", ctxt, tmpObj, owner);
                ctxt.restore();
            }
        }

        // RENDER TAIL:
        var accessSprites = {};
        var accessPointers = {};
        function renderTail(index, ctxt, owner) {
            tmpSkin = accessSprites[index];
            if (!tmpSkin) {
                var tmpImage = new Image();
                tmpImage.onload = function() {
                    this.isLoaded = true;
                    this.onload = null;
                };
                tmpImage.src = ".././img/accessories/access_" + index + ".png";
                accessSprites[index] = tmpImage;
                tmpSkin = tmpImage;
            }
            var tmpObj = accessPointers[index];
            if (!tmpObj) {
                for (var i = 0; i < accessories.length; ++i) {
                    if (accessories[i].id == index) {
                        tmpObj = accessories[i];
                        break;
                    }
                }
                accessPointers[index] = tmpObj;
            }
            if (tmpSkin.isLoaded) {
                ctxt.save();
                ctxt.translate(-20 - (tmpObj.xOff||0), 0);
                if (tmpObj.spin)
                    ctxt.rotate(owner.skinRot);
                ctxt.drawImage(tmpSkin, -(tmpObj.scale/2), -(tmpObj.scale/2), tmpObj.scale, tmpObj.scale);
                ctxt.restore();
            }
        }

        // RENDER TOOL:
        var toolSprites = {};
        function renderTool(obj, variant, x, y, ctxt) {
            var tmpSrc = obj.src + (variant||"");
            var tmpSprite = toolSprites[tmpSrc];
            if (!tmpSprite) {
                tmpSprite = new Image();
                tmpSprite.onload = function() {
                    this.isLoaded = true;
                }
                tmpSprite.src = ".././img/weapons/" + tmpSrc + ".png";
                toolSprites[tmpSrc] = tmpSprite;
            }
            if (tmpSprite.isLoaded)
                ctxt.drawImage(tmpSprite, x+obj.xOff-(obj.length/2), y+obj.yOff-(obj.width/2), obj.length, obj.width);
        }

        // RENDER GAME OBJECTS:
        var gameObjectSprites = {};
        function getResSprite(obj) {
            var biomeID = (obj.y>=config.mapScale-config.snowBiomeTop)?2:((obj.y<=config.snowBiomeTop)?1:0);
            var tmpIndex = (obj.type + "_" + obj.scale + "_" + biomeID);
            var tmpSprite = gameObjectSprites[tmpIndex];
            if (!tmpSprite) {
                var tmpCanvas = document.createElement('canvas');
                tmpCanvas.width = tmpCanvas.height = (obj.scale * 2.1) + outlineWidth;
                var tmpContext = tmpCanvas.getContext('2d');
                tmpContext.translate((tmpCanvas.width / 2), (tmpCanvas.height / 2));
                tmpContext.rotate(UTILS.randFloat(0, Math.PI));
                tmpContext.strokeStyle = outlineColor;
                tmpContext.lineWidth = outlineWidth;
                let colors = [
                    ["#b1d959", "#95b946"],
                    ["#bade6e", "#aac76b"],
                    ["#a7d544", "#86a63f"],
                    ["#b4db62", "#9ebf57"]
                ]
                let select = colors[Math.floor(Math.random() * colors.length)];
                if (obj.type == 0) {
                    var tmpScale;
                    for (var i = 0; i < 2; ++i) {
                        tmpScale = tmpObj.scale * (!i?1:0.5);
                        renderStar(tmpContext, 7, tmpScale, tmpScale * 0.7);
                        tmpContext.fillStyle = !biomeID?(!i?"#9ebf57":"#b4db62"):(!i?"#e3f1f4":"#fff");
                        tmpContext.fill();
                        if (!i)
                            tmpContext.stroke();
                    }
                } else if (obj.type == 1) {
                    if (biomeID == 2) {
                        tmpContext.fillStyle = "#606060";
                        renderStar(tmpContext, 6, obj.scale * 0.3, obj.scale * 0.71);
                        tmpContext.fill();
                        tmpContext.stroke();
                        tmpContext.fillStyle = "#89a54c";
                        renderCircle(0, 0, obj.scale * 0.55, tmpContext);
                        tmpContext.fillStyle = "#a5c65b";
                        renderCircle(0, 0, obj.scale * 0.3, tmpContext, true);
                    } else {
                        renderBlob(tmpContext, 6, tmpObj.scale, tmpObj.scale * 0.7);
                        tmpContext.fillStyle = biomeID?"#e3f1f4":"#89a54c";
                        tmpContext.fill();
                        tmpContext.stroke();
                        tmpContext.fillStyle = biomeID?"#6a64af":"#c15555";
                        var tmpRange;
                        var berries = 4;
                        var rotVal = mathPI2 / berries;
                        for (var i = 0; i < berries; ++i) {
                            tmpRange = UTILS.randInt(tmpObj.scale/3.5, tmpObj.scale/2.3);
                            renderCircle(tmpRange * Math.cos(rotVal * i), tmpRange * Math.sin(rotVal * i),
                                         UTILS.randInt(10, 12), tmpContext);
                        }
                    }
                } else if (obj.type == 2 || obj.type == 3) {
                    tmpContext.fillStyle = (obj.type==2)?(biomeID==2?"#938d77":"#939393"):"#e0c655";
                    renderStar(tmpContext, 3, obj.scale, obj.scale);
                    tmpContext.fill();
                    tmpContext.stroke();
                    tmpContext.fillStyle = (obj.type==2)?(biomeID==2?"#b2ab90":"#bcbcbc"):"#ebdca3";
                    renderStar(tmpContext, 3, obj.scale * 0.55, obj.scale * 0.65);
                    tmpContext.fill();
                }
                tmpSprite = tmpCanvas;
                gameObjectSprites[tmpIndex] = tmpSprite;
            }
            return tmpSprite;
        }

        // GET ITEM SPRITE:
        var itemSprites = [];
        function getItemSprite(obj, asIcon) {
            var tmpSprite = itemSprites[obj.id + (obj.predictEnemyTrap ? 100 : (obj.prediction ? (obj.preplace ? 200 : 300) : 0))];
            if (!tmpSprite || asIcon) {
                var tmpCanvas = document.createElement('canvas');
                tmpCanvas.width = tmpCanvas.height = (obj.scale * 2.5) + outlineWidth +
                    (items.list[obj.id].spritePadding||0);
                var tmpContext = tmpCanvas.getContext('2d');
                tmpContext.translate((tmpCanvas.width / 2), (tmpCanvas.height / 2));
                tmpContext.rotate(asIcon?0:(Math.PI/2));
                tmpContext.strokeStyle = obj.prediction ? obj.preplace ? "#0000ff" : "#ff0000" : outlineColor;
                tmpContext.lineWidth = outlineWidth * (asIcon?(tmpCanvas.width/81):1);
                if (obj.name == "apple") {
                    tmpContext.fillStyle = "#c15555";
                    renderCircle(0, 0, obj.scale, tmpContext);
                    tmpContext.fillStyle = "#89a54c";
                    var leafDir = -(Math.PI / 2);
                    renderLeaf(obj.scale * Math.cos(leafDir), obj.scale * Math.sin(leafDir),
                               25, leafDir + Math.PI/2, tmpContext);
                } else if (obj.name == "cookie") {
                    tmpContext.fillStyle = "#cca861";
                    renderCircle(0, 0, obj.scale, tmpContext);
                    tmpContext.fillStyle = "#937c4b";
                    var chips = 4;
                    var rotVal = mathPI2 / chips;
                    var tmpRange;
                    for (var i = 0; i < chips; ++i) {
                        tmpRange = UTILS.randInt(obj.scale / 2.5, obj.scale / 1.7);
                        renderCircle(tmpRange * Math.cos(rotVal * i), tmpRange * Math.sin(rotVal * i),
                                     UTILS.randInt(4, 5), tmpContext, true);
                    }
                } else if (obj.name == "cheese") {
                    tmpContext.fillStyle = "#f4f3ac";
                    renderCircle(0, 0, obj.scale, tmpContext);
                    tmpContext.fillStyle = "#c3c28b";
                    var chips = 4;
                    var rotVal = mathPI2 / chips;
                    var tmpRange;
                    for (var i = 0; i < chips; ++i) {
                        tmpRange = UTILS.randInt(obj.scale / 2.5, obj.scale / 1.7);
                        renderCircle(tmpRange * Math.cos(rotVal * i), tmpRange * Math.sin(rotVal * i),
                                     UTILS.randInt(4, 5), tmpContext, true);
                    }
                } else if (obj.name == "wood wall" || obj.name == "stone wall" || obj.name == "castle wall") {
                    tmpContext.fillStyle = (obj.name == "castle wall")?"#83898e":(obj.name=="wood wall")?
                        "#a5974c":"#939393";
                    var sides = (obj.name == "castle wall")?4:3;
                    renderStar(tmpContext, sides, obj.scale * 1.1, obj.scale * 1.1);
                    tmpContext.fill();
                    tmpContext.stroke();
                    tmpContext.fillStyle = (obj.name == "castle wall")?"#9da4aa":(obj.name=="wood wall")?
                        "#c9b758":"#bcbcbc";
                    renderStar(tmpContext, sides, obj.scale * 0.65, obj.scale * 0.65);
                    tmpContext.fill();
                } else if (obj.name == "spikes" || obj.name == "greater spikes" || obj.name == "poison spikes" || obj.name == "spinning spikes"){
                    tmpContext.fillStyle = (obj.name == "poison spikes") ? "#7b935d" : "#939393";

                    var tmpScale = (obj.scale * 0.6);
                    renderStar(tmpContext, (obj.name == "spikes") ? 5 : 6, obj.scale, tmpScale);

                    tmpContext.fill();
                    tmpContext.stroke();

                    obj.prediction && (
                        tmpContext.globalAlpha = 0.6,
                        tmpContext.fillStyle = obj.preplace ? "#0000ff" : "#ff0000",
                        renderStar(tmpContext, obj.name == "spikes" ? 5 : 6, obj.scale, tmpScale),
                        tmpContext.fill(),
                        tmpContext.globalAlpha = 1);

                    tmpContext.fillStyle = "#a5974c";
                    renderCircle(0, 0, tmpScale, tmpContext);

                    obj.prediction && (
                        tmpContext.globalAlpha = 0.6,
                        tmpContext.fillStyle = obj.preplace ? "#0000ff" : "#ff0000",
                        renderCircle(0, 0, tmpScale, tmpContext),
                        tmpContext.globalAlpha = 1);

                    tmpContext.fillStyle = "#c9b758";
                    renderCircle(0, 0, tmpScale / 2, tmpContext, true);

                    obj.prediction && (
                        tmpContext.globalAlpha = 0.6,
                        tmpContext.fillStyle = obj.preplace ? "#0000ff" : "#ff0000",
                        renderCircle(0, 0, tmpScale / 2, tmpContext, !0),
                        tmpContext.globalAlpha = 1);
                } else if (obj.name == "windmill" || obj.name == "faster windmill" || obj.name == "power mill") {
                    tmpContext.fillStyle = "#a5974c";
                    renderCircle(0, 0, obj.scale, tmpContext);

                    obj.prediction && (
                        tmpContext.globalAlpha = 0.6,
                        tmpContext.fillStyle = obj.preplace ? "#0000ff" : "#ff0000",
                        renderCircle(0, 0, obj.scale, tmpContext),
                        tmpContext.globalAlpha = 1);

                    tmpContext.fillStyle = "#c9b758";
                    renderRectCircle(0, 0, obj.scale * 1.5, 29, 4, tmpContext);

                    obj.prediction && (
                        tmpContext.globalAlpha = 0.6,
                        tmpContext.fillStyle = obj.preplace ? "#0000ff" : "#ff0000",
                        renderRectCircle(0, 0, obj.scale * 1.5, 29, 4, tmpContext),
                        tmpContext.globalAlpha = 1);

                    tmpContext.fillStyle = "#a5974c";
                    renderCircle(0, 0, obj.scale * 0.5, tmpContext);

                    obj.prediction && (
                        tmpContext.globalAlpha = 0.6,
                        tmpContext.fillStyle = obj.preplace ? "#0000ff" : "#ff0000",
                        renderCircle(0, 0, obj.scale * .5, tmpContext),
                        tmpContext.globalAlpha = 1);
                } else if (obj.name == "mine") {
                    tmpContext.fillStyle = "#939393";
                    renderStar(tmpContext, 3, obj.scale, obj.scale);
                    tmpContext.fill();
                    tmpContext.stroke();
                    tmpContext.fillStyle = "#bcbcbc";
                    renderStar(tmpContext, 3, obj.scale * 0.55, obj.scale * 0.65);
                    tmpContext.fill();
                } else if (obj.name == "sapling") {
                    for (var i = 0; i < 2; ++i) {
                        var tmpScale = obj.scale * (!i?1:0.5);
                        renderStar(tmpContext, 7, tmpScale, tmpScale * 0.7);
                        tmpContext.fillStyle = (!i?"#9ebf57":"#b4db62");
                        tmpContext.fill();
                        if (!i) tmpContext.stroke();
                    }
                } else if (obj.name == "pit trap") {
                    tmpContext.fillStyle = "#a5974c";
                    renderStar(tmpContext, 3, obj.scale * 1.1, obj.scale * 1.1);
                    tmpContext.fill();
                    tmpContext.stroke();

                    obj.prediction && (
                        tmpContext.globalAlpha = 0.6,
                        tmpContext.fillStyle = obj.preplace ? "#0000ff" : "#ff0000",
                        renderStar(tmpContext, 3, obj.scale * 1.1, obj.scale * 1.1),
                        tmpContext.fill(),
                        tmpContext.globalAlpha = 1);

                    tmpContext.fillStyle = outlineColor;
                    renderStar(tmpContext, 3, obj.scale * 0.65, obj.scale * 0.65);
                    tmpContext.fill();

                    obj.prediction && (
                        tmpContext.globalAlpha = 0.6,
                        tmpContext.fillStyle = obj.preplace ? "#0000ff" : "#ff0000",
                        renderStar(tmpContext, 3, obj.scale * .65, obj.scale * .65),
                        tmpContext.fill());
                } else if (obj.name == "boost pad") {
                    tmpContext.fillStyle = "#7e7f82";
                    renderRect(0, 0, obj.scale*2, obj.scale*2, tmpContext);
                    tmpContext.fill();
                    tmpContext.stroke();
                    tmpContext.fillStyle = "#dbd97d";
                    renderTriangle(obj.scale * 1, tmpContext);
                } else if (obj.name == "turret") {
                    tmpContext.fillStyle = "#a5974c";
                    renderCircle(0, 0, obj.scale, tmpContext);
                    tmpContext.fill();
                    tmpContext.stroke();
                    tmpContext.fillStyle = "#939393";
                    var tmpLen = 50;
                    renderRect(0, -tmpLen/2, obj.scale * 0.9, tmpLen, tmpContext);
                    renderCircle(0, 0, obj.scale * 0.6, tmpContext);
                    tmpContext.fill();
                    tmpContext.stroke();
                } else if (obj.name == "platform") {
                    tmpContext.fillStyle = "#cebd5f";
                    var tmpCount = 4;
                    var tmpS = obj.scale * 2;
                    var tmpW = tmpS / tmpCount;
                    var tmpX = -(obj.scale/2);
                    for (var i = 0; i < tmpCount; ++i) {
                        renderRect(tmpX - (tmpW/2), 0, tmpW, obj.scale*2, tmpContext);
                        tmpContext.fill();
                        tmpContext.stroke();
                        tmpX += tmpS / tmpCount;
                    }
                } else if (obj.name == "healing pad") {
                    tmpContext.fillStyle = "#7e7f82";
                    renderRect(0, 0, obj.scale*2, obj.scale*2, tmpContext);
                    tmpContext.fill();
                    tmpContext.stroke();
                    tmpContext.fillStyle = "#db6e6e";
                    renderRectCircle(0, 0, obj.scale * 0.65, 20, 4, tmpContext, true);
                } else if (obj.name == "spawn pad") {
                    tmpContext.fillStyle = "#7e7f82";
                    renderRect(0, 0, obj.scale*2, obj.scale*2, tmpContext);
                    tmpContext.fill();
                    tmpContext.stroke();
                    tmpContext.fillStyle = "#71aad6";
                    renderCircle(0, 0, obj.scale * 0.6, tmpContext);
                } else if (obj.name == "blocker") {
                    tmpContext.fillStyle = "#7e7f82";
                    renderCircle(0, 0, obj.scale, tmpContext);
                    tmpContext.fill();
                    tmpContext.stroke();
                    tmpContext.rotate(Math.PI / 4);
                    tmpContext.fillStyle = "#db6e6e";
                    renderRectCircle(0, 0, obj.scale * 0.65, 20, 4, tmpContext, true);
                }  else if (obj.name == "teleporter") {
                    tmpContext.fillStyle = "#7e7f82";
                    renderCircle(0, 0, obj.scale, tmpContext);
                    tmpContext.fill();
                    tmpContext.stroke();
                    tmpContext.rotate(Math.PI / 4);
                    tmpContext.fillStyle = "#d76edb";
                    renderCircle(0, 0, obj.scale * 0.5, tmpContext, true);
                }
                tmpSprite = tmpCanvas;
                if (!asIcon)
                    itemSprites[obj.id + (obj.predictEnemyTrap ? 100 : (obj.prediction ? (obj.preplace ? 200 : 300) : 0))] = tmpSprite;
            }
            return tmpSprite;
        }

        // RENDER LEAF:
        function renderLeaf(x, y, l, r, ctxt) {
            var endX = x + (l * Math.cos(r));
            var endY = y + (l * Math.sin(r));
            var width = l * 0.4;
            ctxt.moveTo(x, y);
            ctxt.beginPath();
            ctxt.quadraticCurveTo(((x + endX) / 2) + (width * Math.cos(r + Math.PI/2)),
                                  ((y + endY) / 2) + (width * Math.sin(r + Math.PI/2)), endX, endY);
            ctxt.quadraticCurveTo(((x + endX) / 2) - (width * Math.cos(r + Math.PI/2)),
                                  ((y + endY) / 2) - (width * Math.sin(r + Math.PI/2)), x, y);
            ctxt.closePath();
            ctxt.fill();
            ctxt.stroke();
        }

        // RENDER CIRCLE:
        function renderCircle(x, y, scale, tmpContext, dontStroke, dontFill) {
            tmpContext = tmpContext||mainContext;
            tmpContext.beginPath();
            tmpContext.arc(x, y, scale, 0, 2 * Math.PI);
            if (!dontFill) tmpContext.fill();
            if (!dontStroke) tmpContext.stroke();
        }

        // RENDER STAR SHAPE:
        function renderStar(ctxt, spikes, outer, inner) {
            var rot = Math.PI / 2 * 3;
            var x, y;
            var step = Math.PI / spikes;
            ctxt.beginPath();
            ctxt.moveTo(0, -outer);
            for (var i = 0; i < spikes; i++) {
                x = Math.cos(rot) * outer;
                y = Math.sin(rot) * outer;
                ctxt.lineTo(x, y);
                rot += step;
                x = Math.cos(rot) * inner;
                y = Math.sin(rot) * inner;
                ctxt.lineTo(x, y);
                rot += step;
            }
            ctxt.lineTo(0, -outer);
            ctxt.closePath();
        }

        // RENDER RECTANGLE:
        function renderRect(x, y, w, h, ctxt, stroke) {
            ctxt.fillRect(x - (w / 2), y - (h / 2), w, h);
            if (!stroke)
                ctxt.strokeRect(x - (w / 2), y - (h / 2), w, h);
        }

        // RENDER RECTCIRCLE:
        function renderRectCircle(x, y, s, sw, seg, ctxt, stroke) {
            ctxt.save();
            ctxt.translate(x, y);
            seg = Math.ceil(seg / 2);
            for (var i = 0; i < seg; i++) {
                renderRect(0, 0, s * 2, sw, ctxt, stroke);
                ctxt.rotate(Math.PI / seg);
            }
            ctxt.restore();
        }

        function drawSpikeMidpoint() {
    if (!getSetting("SpikeMidKnockback")) return;
    if (!nearestEnemy) return;

    const spikes = getNearestTwoSpikes(nearestEnemy);
    if (!spikes) return;

    const m = getSpikeMidpoint(spikes[0], spikes[1]);

    ctx.beginPath();
    ctx.arc(m.x - camX, m.y - camY, 6, 0, Math.PI * 2);
    ctx.fillStyle = "rgba(255, 80, 80, 0.7)";
    ctx.fill();
}


        // RENDER BLOB:
        function renderBlob(ctxt, spikes, outer, inner) {
            var rot = Math.PI / 2 * 3;
            var x, y;
            var step = Math.PI / spikes;
            var tmpOuter;
            ctxt.beginPath();
            ctxt.moveTo(0, -inner);
            for (var i = 0; i < spikes; i++) {
                tmpOuter = UTILS.randInt(outer + 0.9, outer * 1.2);
                ctxt.quadraticCurveTo(Math.cos(rot + step) * tmpOuter, Math.sin(rot + step) * tmpOuter,
                                      Math.cos(rot + (step * 2)) * inner, Math.sin(rot + (step * 2)) * inner);
                rot += step * 2;
            }
            ctxt.lineTo(0, -inner);
            ctxt.closePath();
        }

        // RENDER TRIANGLE:
        function renderTriangle(s, ctx) {
            ctx = ctx||mainContext;
            var h = s * (Math.sqrt(3)/2);
            ctx.beginPath();
            ctx.moveTo(0, -h / 2);
            ctx.lineTo( -s / 2, h / 2);
            ctx.lineTo(s / 2, h / 2);
            ctx.lineTo(0, -h / 2);
            ctx.fill();
            ctx.closePath();
        }

