        function getSpikeMidpointTarget() {
    if (!nearestEnemy) return null;


    let spikes = visibleObjects.filter(o =>
        o.id > 5 && o.id < 10 &&
        o.owner &&
        (o.owner.sid === myPlayer.sid || isAlly(o.owner.sid))
    );

    if (spikes.length < 2) return null;

    let best = null;
    let bestDist = Infinity;

    for (let i = 0; i < spikes.length; i++) {
        for (let j = i + 1; j < spikes.length; j++) {

            let s1 = spikes[i];
            let s2 = spikes[j];


            let mx = (s1.x + s2.x) / 2;
            let my = (s1.y + s2.y) / 2;


            let spikeGap = UTILS.getDistance(s1.x, s1.y, s2.x, s2.y);
            if (spikeGap > 110 || spikeGap < 55) continue;


            let enemyToMid = UTILS.getDistance(nearestEnemy.x2, nearestEnemy.y2, mx, my);
            if (enemyToMid > 140) continue;

            if (enemyToMid < bestDist) {
                bestDist = enemyToMid;
                best = { x: mx, y: my };
            }
        }
    }

    return best;
}

        function getNearestTwoSpikes(enemy, maxDist = 220) {
    let spikes = visibleObjects.filter(o =>
        o.id > 5 && o.id < 10 &&
        (o.owner.sid === myPlayer.sid || isAlly(o.owner.sid)) &&
        UTILS.getDistance(enemy.x2, enemy.y2, o.x, o.y) < maxDist
    );

    if (spikes.length < 2) return null;

    spikes.sort((a, b) =>
        UTILS.getDistance(enemy.x2, enemy.y2, a.x, a.y) -
        UTILS.getDistance(enemy.x2, enemy.y2, b.x, b.y)
    );

    return [spikes[0], spikes[1]];
}


        function getSpikeMidpoint(spikeA, spikeB) {
    return {
        x: (spikeA.x + spikeB.x) / 2,
        y: (spikeA.y + spikeB.y) / 2
    };
}


function canSpikeMidKnockback(enemy) {
    if (!enemy) return false;
    if (!getSetting("SpikeMidKnockback")) return false;
    if (autoaim) return false;
    if (primaryReload[myPlayer.sid] !== 1) return false;

    const spikes = getNearestTwoSpikes(enemy);
    if (!spikes) return false;

    const midpoint = getSpikeMidpoint(spikes[0], spikes[1]);

    const distEnemyToMid = UTILS.getDistance(enemy.x2, enemy.y2, midpoint.x, midpoint.y);
    if (distEnemyToMid > 140) return false;

    // Check spikes are not too far apart
    const spikeGap = UTILS.getDistance(spikes[0].x, spikes[0].y, spikes[1].x, spikes[1].y);
    if (spikeGap > 110 || spikeGap < 40) return false;

    // Check knockback would push enemy towards midpoint
    const knockAngle = Math.atan2(midpoint.y - enemy.y2, midpoint.x - enemy.x2);
    const expectedX = enemy.x2 + Math.cos(knockAngle) * 110;
    const expectedY = enemy.y2 + Math.sin(knockAngle) * 110;
    const dist = UTILS.getDistance(expectedX, expectedY, midpoint.x, midpoint.y);

    return dist < 50;
}


function canVelocitySpikeTick() {
            if (!nearestEnemy) return;

            let spikes = visibleObjects.filter(object => object.id > 5 && object.id < 10 && (object.owner.sid == myPlayer.sid || isAlly(object.owner.sid)));
            let trap = visibleObjects.filter(object => object.id == 15 && UTILS.getDistance(nearestEnemy.x2, nearestEnemy.y2, object.x, object.y) <= 50 && (object.owner.sid == myPlayer.sid || isAlly(object.owner.sid)))[0];

            let isEnemyInSpike = false;

            let posX = nearestEnemy.x2 + 111 * (.3 + (items.weapons[myPlayer.weapons[0]].knock || 0)) * Math.cos(Math.atan2(nearestEnemy.y2 - myPlayer.y2, nearestEnemy.x2 - myPlayer.x2));
            let posY = nearestEnemy.y2 + 111 * (.3 + (items.weapons[myPlayer.weapons[0]].knock || 0)) * Math.sin(Math.atan2(nearestEnemy.y2 - myPlayer.y2, nearestEnemy.x2 - myPlayer.x2));

            for (let object of spikes) {
                if (UTILS.getDistance(nearestEnemy.xVel, nearestEnemy.yVel, object.x, object.y) < (35 + object.scale)) {
                    isEnemyInSpike = true;
                } else {
                    if (trap) {
                        if (nearestEnemy.spikeDamage > 0) {
                            isEnemyInSpike = true;
                        }
                    } else {
                        if (UTILS.getDistance(posX, posY, object.x, object.y) < (35 + object.scale)) {
                            isEnemyInSpike = true;
                        }
                    }
                }

                if (isEnemyInSpike) break;
            }

            if (isEnemyInSpike) {
                return (myPlayer.weapons[0] == 4 || myPlayer.weapons[0] == 5) && UTILS.getDistance(nearestEnemy.xVel, nearestEnemy.yVel, myPlayer.xVel, myPlayer.yVel) <= (35 * 1.8 + items.weapons[myPlayer.weapons[0]].range)
                && primaryReload[myPlayer.sid] == 1 && !autoaim;
            }
        }


       function canSpikeTick() {
    if (!nearestEnemy) return false;
    if (autoaim) return false;
    if (trapBreaked) return false;

    if (myPlayer.weapons[0] !== 4 && myPlayer.weapons[0] !== 5) return false;
    if (primaryReload[myPlayer.sid] !== 1) return false;
    if (secondaryReload[myPlayer.sid] !== 1) return false;


    let spikeNear = visibleObjects.some(o =>
        o.id > 5 && o.id < 10 &&
        (o.owner.sid === myPlayer.sid || isAlly(o.owner.sid)) &&
        UTILS.getDistance(nearestEnemy.x2, nearestEnemy.y2, o.x, o.y) <= (35 + o.scale)
    );

    return spikeNear;
}



       function canPredictSpikeTick() {
    if (!canSpikeTick()) return false;

    let trap = visibleObjects.find(o =>
        o.id === 15 &&
        (o.owner.sid === myPlayer.sid || isAlly(o.owner.sid)) &&
        UTILS.getDistance(nearestEnemy.x2, nearestEnemy.y2, o.x, o.y) <= 55
    );

    if (!trap) return false;

    if (myPlayer.weapons[1] !== 10) return false;
    if (secondaryReload[myPlayer.sid] !== 1) return false;

    const weapon = myPlayer.weapons[1];
    const dmg =
        items.weapons[weapon].dmg *
        (items.weapons[weapon].sDmg || 1) *
        config.weaponVariants[(myPlayer.weaponVariants[weapon] || 1)].val *
        (isBoughtHat(40, 0) ? 3.3 : 1);

    return trap.health <= dmg;
}

        function isRetrapLoop() {
    if (!nearestEnemy) return false;

    const myTrap = visibleObjects.find(o =>
        o.id === 15 &&
        (o.owner.sid === myPlayer.sid || isAlly(o.owner.sid)) &&
        UTILS.getDistance(myPlayer.x2, myPlayer.y2, o.x, o.y) <= (o.scale + 50)
    );

    const enemyTrap = visibleObjects.find(o =>
        o.id === 15 &&
        o.owner &&
        o.owner.sid === nearestEnemy.sid &&
        UTILS.getDistance(nearestEnemy.x2, nearestEnemy.y2, o.x, o.y) <= (o.scale + 50)
    );

    if (myTrap && enemyTrap) {
        retrapLoopTicks++;
    } else {
        retrapLoopTicks = 0;
    }

    return retrapLoopTicks >= 3;
}

        function canBreakRetrapWithSpikeTick() {
    if (!nearestEnemy) return false;
    if (autoTrapTick || (instaKill && instaKill.length)) return false;

    if (UTILS.getDistance(myPlayer.x2, myPlayer.y2, nearestEnemy.x2, nearestEnemy.y2) > 160) return false;

    if (primaryReload[myPlayer.sid] !== 1) return false;

    // Work when: retrap loop OR enemy has trap near them
    const enemyHasTrap = visibleObjects.some(o =>
        o.id === 15 && o.owner && o.owner.sid === nearestEnemy.sid &&
        UTILS.getDistance(nearestEnemy.x2, nearestEnemy.y2, o.x, o.y) <= 50
    );
    if (!isRetrapLoop() && !enemyHasTrap) return false;

    return true;
}

        function doRetrapBreakSpikeTick() {
    const enemyTrap = visibleObjects.find(o =>
        o.id === 15 && o.owner && o.owner.sid === nearestEnemy.sid &&
        UTILS.getDistance(nearestEnemy.x2, nearestEnemy.y2, o.x, o.y) <= 50
    );
    const myTrap = visibleObjects.find(o =>
        o.id === 15 && o.owner && (o.owner.sid === myPlayer.sid || isAlly(o.owner.sid)) &&
        UTILS.getDistance(nearestEnemy.x2, nearestEnemy.y2, o.x, o.y) <= 50
    );
    let target = enemyTrap || myTrap;
    if (!target) return;
    const angle = Math.atan2(target.y - myPlayer.y2, target.x - myPlayer.x2);
    my.autoAim = true;
    if (myPlayer.weapons[1] === 10 && secondaryReload[myPlayer.sid] === 1) {
        selectWeapon(myPlayer.weapons[1]);
    } else {
        selectWeapon(myPlayer.weapons[0]);
    }
    sendAtck(1, angle);
    sendAtck(0, angle);
    retrapLoopTicks = 0;
    if (getSetting("chatlog")) {
        addChatLog("Retrap -> SpikeTick", "", "#ff6666", false, true);
    }
}




        function doSpikeTick() {
    if (!canPredictSpikeTick()) return;

    const angle = Math.atan2(
        nearestEnemy.y2 - myPlayer.y2,
        nearestEnemy.x2 - myPlayer.x2
    );

    autoaim = true;


    selectWeapon(myPlayer.weapons[1]);
    sendAtck(1, angle);
    sendAtck(0, angle);


    game.tickBase(() => {
        selectWeapon(myPlayer.weapons[0]);
        sendAtck(1, angle);
        sendAtck(0, angle);
        autoaim = false;
    }, ping > 80 ? 2 : 1);
}


        function smartTrapBreakAndSpikeTick() {
    if (!nearestEnemy || autoaim) return;

    // Find enemy trap near enemy
    const trap = visibleObjects.find(o =>
        o.id === 15 &&
        o.owner &&
        o.owner.sid === nearestEnemy.sid &&
        UTILS.getDistance(nearestEnemy.x2, nearestEnemy.y2, o.x, o.y) <= 50
    );
    if (!trap) return;

    // Also find our trap near enemy
    const myTrap = visibleObjects.find(o =>
        o.id === 15 &&
        o.owner &&
        (o.owner.sid === myPlayer.sid || isAlly(o.owner.sid)) &&
        UTILS.getDistance(nearestEnemy.x2, nearestEnemy.y2, o.x, o.y) <= 50
    );
    const target = trap || myTrap;
    if (!target) return;
    if (!canOneHitTrap(target)) return;

    const dir = Math.atan2(target.y - myPlayer.y2, target.x - myPlayer.x2);

    my.autoAim = true;
    // Use hammer if we have it, otherwise primary
    if (myPlayer.weapons[1] === 10 && secondaryReload[myPlayer.sid] === 1) {
        selectWeapon(10);
    } else {
        selectWeapon(myPlayer.weapons[0]);
    }
    sendAtck(1, dir);
    sendAtck(0, dir);

    nextTick(() => {
        my.autoAim = true;
        selectWeapon(myPlayer.weapons[0]);
        buyEquip(7, 0);
        sendAutoGather();

        nextTick(() => {
            if (player.reloads[53] === 0) {
                buyEquip(53, 0);
            }
            sendAutoGather();
            my.autoAim = false;
        }, 1);
    }, 1);
}

function doSpikeMidKnockback() {
    const spikes = getNearestTwoSpikes(nearestEnemy);
    if (!spikes) return;

    // Verify gap is valid
    const gap = UTILS.getDistance(spikes[0].x, spikes[0].y, spikes[1].x, spikes[1].y);
    if (gap > 110 || gap < 40) return;

    const mid = getSpikeMidpoint(spikes[0], spikes[1]);

    const angle = Math.atan2(mid.y - myPlayer.y2, mid.x - myPlayer.x2);

    my.autoAim = true;
    selectWeapon(myPlayer.weapons[0]);

    sendAtck(1, angle);
    sendAtck(0, angle);

    game.tickBase(() => {
        my.autoAim = false;
    }, 1);

    if (getSetting("chatlog")) {
        addChatLog("Spike -> Midpoint", "", "#ff4444", false, true);
    }
}

        function canOneHitTrap(trap) {
    if (!trap) return false;
    if (myPlayer.weapons[1] !== 10) return false;
    if (secondaryReload[myPlayer.sid] !== 1) return false;

    const hammer = items.weapons[10];
    const dmg =
        hammer.dmg *
        (hammer.sDmg || 1) *
        config.weaponVariants[(myPlayer.weaponVariants[10] || 1)].val *
        (isBoughtHat(40, 0) ? 3.3 : 1);

    return trap.health <= dmg &&
        UTILS.getDistance(myPlayer.x2, myPlayer.y2, trap.x, trap.y) <=
        (trap.scale + hammer.range);
}



