        // Centralized placement label helper that respects settings
        function showPlacementLabel(x, y, text, color, opts){
            try{
                if(!settings) return;
                // Map text -> per-style settings
                var map = {
                    place: { enabled: settings.label_place_enabled, color: settings.label_place_color },
                    autoplace: { enabled: settings.label_autoplace_enabled, color: settings.label_autoplace_color },
                    preplace: { enabled: settings.label_preplace_enabled, color: settings.label_preplace_color },
                    replace: { enabled: settings.label_replace_enabled, color: settings.label_replace_color }
                };

                var cfg = map[text] || map.place;
                if(!cfg.enabled) return;
                color = color || cfg.color;
                // Use global numeric settings, but allow opts to override
                var size = (opts && opts.size) ? Number(opts.size) : Number(settings.label_size);
                var speed = (opts && opts.speed) ? Number(opts.speed) : Number(settings.label_speed);
                var life = (opts && opts.life) ? Number(opts.life) : Number(settings.label_life);
                if(isNaN(size) || size <= 0) size = 36;
                if(isNaN(speed) || speed <= 0) speed = 0.18;
                if(isNaN(life) || life <= 0) life = 800;
                textManager.showText(x, y, size, speed, life, text, color);
            }catch(e){}
        }

