        function lineInCircle(x, y, x2, y2, circleX, circleY, scale){
            let lineVec = {x: x2 - x, y: y2 - y};
            let lineToCircleVec = {x: circleX - x, y: circleY - y};

            let projection = (lineToCircleVec.x * lineVec.x + lineToCircleVec.y * lineVec.y) / (lineVec.x * lineVec.x + lineVec.y * lineVec.y);
            let closestPoint = {x: x + projection * lineVec.x, y: y + projection * lineVec.y};

            if(closestPoint.x >= Math.min(x, x2) && closestPoint.x <= Math.max(x, x2) && closestPoint.y >= Math.min(y, y2) && closestPoint.y <= Math.max(y, y2)){
                return UTILS.getDistance(closestPoint.x, closestPoint.y, circleX, circleY) < scale;
            }
        }

        function isAlly(sid){
            if(myPlayer.team){
                for(var i = 0; i < alliancePlayers.length;i += 2){
                    if(alliancePlayers[i] == sid){
                        return true;
                    }
                }
            }
        }

        function isObjectMine(object) {
            return object?.owner?.sid === myPlayer.sid;
        }

        // Remove radial component of movement towards a point (px,py).
        // Keeps lateral manual input while removing forward movement into the removed object.
        function removeRadialMovement(px, py){
            try{
                // If the movement auto-stop feature is disabled, do nothing.
                if(!(settings && settings.autostop_before_collision)) return;
                if(!myPlayer) return;
                // If player is currently inside a trap, do not remove radial movement / autostop
                try{
                    // Only treat being "in a trap" as blocking autostop when the trap
                    // is owned by an enemy (owner exists, owner.sid != myPlayer.sid, and not an ally).
                    const inEnemyTrapNow = visibleObjects && visibleObjects.some(o => o && o.id == 15 && o.owner && o.owner.sid != myPlayer.sid && !isAlly(o.owner.sid) && typeof o.x === 'number' && typeof o.y === 'number' && UTILS.getDistance(myPlayer.x2, myPlayer.y2, o.x, o.y) <= (o.scale + (myPlayer.scale || 0)));
                    if(inEnemyTrapNow) return;
                }catch(e){}
                // If moving fast, skip autostop РІР‚вЂќ let momentum carry the player through
                try{
                    const currentSpeedNow = getPlayerSpeed();
                    if(currentSpeedNow > 66) {
                        try{ console.log('[Mod] removeRadialMovement: skipping autostop due to high speed', currentSpeedNow); }catch(e){}
                        return;
                    }
                }catch(e){}
                // If manual input exists, check if it's toward or away from spike
                const manualAngle = (typeof getMoveDir === 'function' ? getMoveDir() : undefined);
                if(manualAngle !== undefined){
                    const dirToSpike = Math.atan2(py - myPlayer.y2, px - myPlayer.x2);
                    let angleDiff = Math.abs(manualAngle - dirToSpike);
                    if(angleDiff > Math.PI) angleDiff = 2 * Math.PI - angleDiff;
                    // If moving away (angleDiff > PI/2), allow movement
                    if(angleDiff > Math.PI / 2){
                        // Do not block movement
                        return;
                    }
                }
                // Otherwise, block forward movement: clear predicted move angle and
                // tell the server to stop movement but keep local key state intact.
                // Set a short future cooldown (tick + 1) so the io.send wrapper will
                // briefly suppress further movement angle sends while the player is
                // still holding movement keys. This ensures the server-side position
                // is actually stopped and auto-break can proceed without requiring
                // the user to release the key.
                predictMoveAngle = null;
                try{ if(settings && settings.autostop_before_collision) stopMovementServerOnly(); }catch(e){}
                // Visual label to indicate we removed forward movement (autostop)
                try{
                    if(typeof textManager !== 'undefined' && myPlayer && settings && settings.label_autostop_enabled){
                        var _as_size2 = Number(settings.label_size) || 20;
                        var _as_speed2 = Number(settings.label_speed) || 0.12;
                        var _as_life2 = Number(settings.label_life) || 600;
                        var _as_color2 = settings.label_autostop_color || "#ff5252";
                        try{ textManager.showText(myPlayer.x2, myPlayer.y2 - (myPlayer.scale || 0) - 30, _as_size2, _as_speed2, _as_life2, "AUTO STOP", _as_color2); }catch(e){}
                    }
                }catch(e){}
                stopMovementTick = Math.max(stopMovementTick, (typeof tick !== 'undefined' ? tick + 1 : 1));
            }catch(e){}
        }

