        function checkPredictObjects(angles){
            for(let object of angles.filter((object) => object.perfect)){
                if(!isAutoPlaceAngle(object)) continue;
                addPredictObject(object.id, object.angle, false);
            }

            for(let object of angles.filter((object) => object.placeable)){
                if(!isAutoPlaceAngle(object)) continue;
                addPredictObject(object.id, object.angle, false);
            }
        }



function getPrePlaceAngles(id, customObjects, scanType = "Fast"){
    // Prefer live menu selection when present
    try{
        var el = document.getElementById('preplacer_mode');
        if(el && el.value) scanType = el.value;
        else {
            // fallback to settings stored value if available
            var s = getPreplacerValue && getPreplacerValue('preplacer_mode');
            if(s) scanType = s;
        }
    }catch(e){}



    // SCAN TYPE 1: Fast - Changes based on distance
    if(scanType === "Fast" && nearestEnemy){
        const angles = [];
        for(let i = 0; i < 36; i++){
            const angle = UTILS.toRad(i * (360 / 36));
            angles.push({id: id, angle: angle, placeable: canPlace(id, angle, customObjects), ...getConfig(id, angle)});
        }
        getPerfectAngles(angles);
        return angles;
    }


    // SCAN TYPE 2: Balanced - Changes based on distance
    if(scanType === "Balanced" && nearestEnemy){
        const angles = [];
        for(let i = 0; i < 120; i++){
            const angle = UTILS.toRad(i * (360 / 120));
            angles.push({id: id, angle: angle, placeable: canPlace(id, angle, customObjects), ...getConfig(id, angle)});
        }
        getPerfectAngles(angles);
        return angles;
    }

    // SCAN TYPE 3: ADAPTIVE - Changes based on distance
    if(scanType === "Accurate" && nearestEnemy){
        const angles = [];
        for(let i = 0; i < 360; i++){
            const angle = UTILS.toRad(i * (360 / 360));
            angles.push({id: id, angle: angle, placeable: canPlace(id, angle, customObjects), ...getConfig(id, angle)});
        }
        getPerfectAngles(angles);
        return angles;
    }
}

        function getPerfectAngles(angles){
            for(let i in angles){
                angles[i].perfect = false;

                if(i < 1) continue;

                if(angles[i].placeable && !angles[i - 1].placeable){
                    angles[i].perfect = true;
                }

                if(angles[i - 1].placeable && !angles[i].placeable){
                    angles[i - 1].perfect = true;
                }
            }
        }
// Funzione per ottenere valori dal menu preplacer
function getPreplacerValue(settingName) {
    const input = document.getElementById(settingName);
    if (input && input.value !== "") {
        return parseFloat(input.value);
    }
    return settings[settingName];
}
// --- Scan visuals for debugging autoplacer angles ---
var scanVisuals = [];
function addScanVisuals(angles){
    try{
        const now = Date.now();
        for(const a of angles){
            scanVisuals.push({ x: a.x, y: a.y, angle: a.angle, placeable: !!a.placeable, perfect: !!a.perfect, t: now });
        }
        // cap to recent visuals
        if(scanVisuals.length > 2000) scanVisuals.splice(0, scanVisuals.length - 2000);
    }catch(e){}
}

// Preplacer visual debug overlays (rays and highlighted spikes)
var preplacerVisuals = [];
function addPreplacerVisual(v){
    try{
        v.t = Date.now();
        preplacerVisuals.push(v);
        if(preplacerVisuals.length > 2000) preplacerVisuals.splice(0, preplacerVisuals.length - 2000);
    }catch(e){}
}


