// Funzione isPrePlaceAngle aggiornata: usa i valori hardcoded forniti dall'utente
// (non legge piР“в„– i valori modificabili dal menu; il toggle del menu `spampreplace`/`spamPrePlacer` Р“РЃ comunque rispettato)

function isPrePlaceAngle(config, prePlaceObject){
    // If there isnt an enemy or the preplacer is off, return
    if(!nearestEnemy || !settings.preplacer) return false;

    // Check distance to enemy, if too far then return
    const distToEnemy = UTILS.getDistance(myPlayer.x2, myPlayer.y2, nearestEnemy.x2, nearestEnemy.y2);
    if(distToEnemy > prePlaceObject.activationDistance) return false;

    // Now we are in condition of actually placing

    // Check if we can actually place the spike
    let canPlaceSpike = config.id == myPlayer.items[2] && !isItemLimit(myPlayer.items[2]);

    // Check if we can actually place the trap
    let canPlaceTrap = config.id == myPlayer.items[4] && !isItemLimit(myPlayer.items[4]);

    // Some important checks
    // Check Enviroment for my Current traps and spikes and also for enemy spieks and traps
    let myTraps = visibleObjects.filter(object => object.id == 15 && (object.owner.sid == myPlayer.sid || isAlly(object.owner.sid)));
    let mySpikes = visibleObjects.filter(object => object.id > 5 && object.id < 10 && (object.owner.sid == myPlayer.sid || isAlly(object.owner.sid)));
    let enemySpikes = visibleObjects.filter(object => object.id > 5 && object.id < 10 && object.owner && object.owner.sid != myPlayer.sid && !isAlly(object.owner.sid));
    let enemyTraps = visibleObjects.filter(object => object.id == 15 && object.owner && object.owner.sid != myPlayer.sid && !isAlly(object.owner.sid));

    // Check if im trapped, 50 is the value of the player scale
    let imTrapped = enemyTraps.some(trap => UTILS.getDistance(myPlayer.x2, myPlayer.y2, trap.x, trap.y) <= (trap.scale + 50));

    // Check if enemy is trapped
    let enemyTrapped = myTraps.some(trap => UTILS.getDistance(nearestEnemy.x2, nearestEnemy.y2, trap.x, trap.y) <= (trap.scale + 50));

    // Check if enemy will be trapped, if he is already trapped, dont check
    let enemyWillBeTrapped = myTraps.some(trap => UTILS.getDistance(nearestEnemy.xVel, nearestEnemy.yVel, trap.x, trap.y) <= (trap.scale + 50) && !enemyTrapped);

    // Check if the spike i place will touch enemy (no velocity prediction)
    let spikeWillTouchEnemy = UTILS.getDistance(config.x, config.y, nearestEnemy.x2, nearestEnemy.y2) <= (config.scale + 35);

    // Check if the spike i place will touch enemy (with velocity prediction)
    let spikeWillTouchEnemyVel = UTILS.getDistance(config.x, config.y, nearestEnemy.xVel, nearestEnemy.yVel) <= (config.scale + 35);

    // Check if current spike placement will block line of sight to enemy
    let spikeWillBlockLOS = UTILS.lineInRect(config.x - config.scale, config.y - config.scale, config.x + config.scale, config.y + config.scale, myPlayer.x2, myPlayer.y2, nearestEnemy.x2, nearestEnemy.y2);
    let dist;
    // Check if spike placement is on the trap where enemy currently is
    let spikeOnEnemyTrap = false;
    for(let trap of myTraps){
        // Check if enemy is on this trap
        if(UTILS.getDistance(trap.x, trap.y, nearestEnemy.x2, nearestEnemy.y2) <= (trap.scale + 50)){
            // Check if spike IS being placed on this same trap
            dist = UTILS.getDistance(trap.x, trap.y, config.x, config.y)
            if(UTILS.getDistance(trap.x, trap.y, config.x, config.y) < (trap.scale + config.scale)){

                spikeOnEnemyTrap = true;
                break;
            }
        }
}
    // Check if enemy can be knockbacked into antoher spike with current spike placement
    let enemyCanBeKnockbacked = false;
    if(spikeWillTouchEnemy || spikeWillTouchEnemyVel){
        let knockbackAngle = Math.atan2(nearestEnemy.y2 - config.y, nearestEnemy.x2 - config.x);
        let projectedX = nearestEnemy.x2 + 200 * Math.cos(knockbackAngle);
        let projectedY = nearestEnemy.y2 + 200 * Math.sin(knockbackAngle);
        for(let spike of mySpikes){
            if(UTILS.lineInRect(spike.x - spike.scale, spike.y - spike.scale, spike.x + spike.scale, spike.y + spike.scale, nearestEnemy.x2, nearestEnemy.y2, projectedX, projectedY)){
                enemyCanBeKnockbacked = true;
                break;
            }
        }
    }




    // ACTUAL PLACEMENT LOGIC

     /* Spam Spike Tick:
    If the settings is true
    If autoTrapTick is true
    if i can place a spike and that spike will touch enemy
    then place a spike for the spiketick
    */
    if(settings.spamSpikeTick && autoTrapTick && canPlaceSpike && (spikeWillTouchEnemy || spikeWillTouchEnemyVel))
        return true;

    /* First Priority:
    if the priority setting is set to be true
    if enemy is currently trapped or he will be trapped
    if i can place a spike that is gonna hit him or will hit him
    if the spike isnt placed on the trap where enemy current is
    then place the fucking spike duh
    */
    if( canPlaceSpike && (enemyTrapped || enemyWillBeTrapped) && (spikeWillTouchEnemy || spikeWillTouchEnemyVel) && !spikeOnEnemyTrap)
        return true;

    /* Second Priority:
    if the priority setting is set to be true
    if we can place a spike thats gona knockback enemy into another spike
    place the spike
    */
    if(canPlaceSpike && (spikeWillTouchEnemy || spikeWillTouchEnemyVel) && enemyCanBeKnockbacked)
    {
        smartTick = true;
        return true;
    }
    /* 3rd Priority:
    if the setting priority is set true
    if we can place a trap place it
    */
   if(canPlaceTrap && !autoTrapTick && !enemyTrapped)
        return true


    // Default return if no place is met
    return false;
}


