    let last = performance.now();
    function frame(t) {
        const dt = (t - last) / 1000;
        last = t;
        ctx.clearRect(0,0,innerWidth, innerHeight);
        const g = ctx.createLinearGradient(0,0,innerWidth,innerHeight);
        g.addColorStop(0, "rgba(8,12,22,1)");
        g.addColorStop(0.35, "rgba(12,20,40,0.9)");
        g.addColorStop(1, "rgba(4,12,20,1)");
        ctx.fillStyle = g;
        ctx.fillRect(0,0,innerWidth, innerHeight);

        for (let i=0;i<3;i++) {
            const x = innerWidth * (0.2 + i*0.33 + Math.sin(t/6000 + i) * 0.03);
            const y = innerHeight * (0.25 + Math.cos(t/6000 + i) * 0.04);
            const r = 280 + i*120;
            const grad = ctx.createRadialGradient(x,y,r*0.1, x,y,r);
            grad.addColorStop(0, `rgba(${50 + i*30}, ${80 + i*10}, ${160 + i*20}, 0.18)`);
            grad.addColorStop(1, "rgba(10,10,12,0)");
            ctx.fillStyle = grad;
            ctx.beginPath();
            ctx.arc(x,y,r,0,Math.PI*2);
            ctx.fill();
        }

        for (const p of particles) {
            p.x += p.vx * dt * 60;
            p.y += p.vy * dt * 60;
            if (p.x < -20) p.x = innerWidth + 20;
            if (p.x > innerWidth + 20) p.x = -20;
            if (p.y < -20) p.y = innerHeight + 20;
            if (p.y > innerHeight + 20) p.y = -20;
            ctx.beginPath();
            ctx.fillStyle = `hsla(${p.hue}, 86%, 62%, ${p.alpha})`;
            ctx.arc(p.x, p.y, p.r, 0, Math.PI*2);
            ctx.fill();
        }

        requestAnimationFrame(frame);
    }
    requestAnimationFrame(frame);

    let sessionSalt = (CONFIG.saltPerSession ? crypto.getRandomValues(new Uint8Array(16)) : new TextEncoder().encode("static_salt"));
    async function deriveKeyFromPassword(password) {
        const enc = new TextEncoder();
        const pwKey = await crypto.subtle.importKey("raw", enc.encode(password), {name: "PBKDF2"}, false, ["deriveBits"]);
        const derived = await crypto.subtle.deriveBits({
            name: "PBKDF2",
            salt: sessionSalt,
            iterations: CONFIG.pbkdf2Iterations,
            hash: "SHA-256"
        }, pwKey, 256);
        return Array.from(new Uint8Array(derived)).map(b => b.toString(16).padStart(2,"0")).join("");
    }
