        function getPlayerInfo(player, type) {
            if (!player) return null;

            const playerPrimary = player.weapons[0] || 5;
            const playerSecondary = player.weapons[1] || 15;
            const primaryVariant = player.weaponVariants[playerPrimary] ?? 2;
            const secondaryVariant = player.weaponVariants[playerSecondary] ?? 2;
            var tankMultiplier = 1;
            if (player == myPlayer) {
                if (isBoughtHat(40, 0)) {
                    tankMultiplier = 3.3;
                }
            }
            else {
                tankMultiplier = 3.3;
            }

            const TOOL_HAMMER = 0, AXE = 1, GREAT_AXE = 2, SHORT_SWORD = 3, KATANA = 4, POLEARM = 5;
            const BAT = 6, DAGGERS = 7, STICK = 8, BOW = 9, HAMMER = 10, SHIELD = 11;
            const CROSSBOW = 12, REPEATER = 13, MCGRABBY = 14, MUSKET = 15;

            const secondaryWeapons = {
                [BOW]: "bow", [HAMMER]: "hammer", [SHIELD]: "shield",
                [CROSSBOW]: "crossbow", [REPEATER]: "repeater crossbow",
                [MCGRABBY]: "mcgrabby", [MUSKET]: "musket"
            };

            const primaryWeapons = {
                [TOOL_HAMMER]: "tool hammer", [AXE]: "axe", [GREAT_AXE]: "great axe",
                [SHORT_SWORD]: "short sword", [KATANA]: "katana", [POLEARM]: "polearm",
                [BAT]: "bat", [DAGGERS]: "daggers", [STICK]: "stick"
            };

            const getVariantMultiplier = (variant) => config.weaponVariants[variant]?.val || 1;

            if (type == "secondaryWeapon") return secondaryWeapons[playerSecondary];
            if (type == "primaryWeapon") return primaryWeapons[playerPrimary];
            if (type == "primaryVariant") return primaryVariant;
            if (type == "secondaryVariant") return secondaryVariant;
            if (type == "primaryRange") return items.weapons[playerPrimary].range;
            if (type == "secondaryRange") return items.weapons[playerSecondary].range;
            if (type == "primaryDmg") return items.weapons[playerPrimary].dmg * 1.5 * getVariantMultiplier(primaryVariant);
            if (type == "primaryStructureDmg") return items.weapons[playerPrimary].dmg * (items.weapons[playerPrimary].sDmg || 1) * getVariantMultiplier(primaryVariant) * tankMultiplier;
            if (type == "secondaryDmg") {
                if (playerSecondary == HAMMER) return items.weapons[playerSecondary].dmg * 1.5 * getVariantMultiplier(secondaryVariant);
                if (playerSecondary == BOW) return 15;
                if (playerSecondary == CROSSBOW) return 30;
                if (playerSecondary == REPEATER) return 35;
                if (playerSecondary == MUSKET) return 50;
                return 0;
            }
            if (type == "secondaryStructureDmg") {
                if (playerSecondary == HAMMER) return items.weapons[playerSecondary].dmg * (items.weapons[playerSecondary].sDmg || 1) * getVariantMultiplier(secondaryVariant) * tankMultiplier;
                return 0;
            }
            if (type == "primaryKnockback") return items.weapons[playerPrimary].knock || 0;
            return null;
        }

        function isPlayerCanInsta(){
            if(!nearestEnemy) return;

            let damage = 0;
            if(primaryReload[nearestEnemy.sid] == 1){
                let primaryWeapon = nearestEnemy.weapons[0] ? nearestEnemy.weapons[0] : null;
                let primaryVariant = 0;

                if(primaryWeapon != null){
                    primaryVariant = nearestEnemy.weaponVariants[primaryWeapon];
                } else {
                    primaryVariant = 3;
                    primaryWeapon = 5;
                }

                damage += items.weapons[primaryWeapon].dmg * 1.5 * config.weaponVariants[primaryVariant].val;
            }

            if(secondaryReload[nearestEnemy.sid] == 1){
                let secondaryWeapon = nearestEnemy.weapons[1] ? nearestEnemy.weapons[1] : 15;
                if(items.weapons[secondaryWeapon].projectile != undefined){
                    damage += items.projectiles[items.weapons[secondaryWeapon].projectile].dmg;
                } else {
                    damage += items.weapons[secondaryWeapon].dmg * config.weaponVariants[nearestEnemy.weaponVariants[secondaryWeapon]].val;
                }
            }

            if(turretReload[nearestEnemy.sid] == 1){
                damage += 25;
            }

            if(damage >= 100) return true;
        }

