    // Expose the internal `settings` object to the global window for console access.
    // We do this outside the webpack bundle to avoid modifying module code and
    // to prevent syntax issues inside packaged modules.
    (function(){
        try{
            var tries = 0;
            var maxTries = 100; // ~10s if using 100ms interval
            var id = setInterval(function(){
                try{
                    if(typeof window !== 'undefined' && typeof settings !== 'undefined'){
                        try{ window.settings = settings; }catch(e){}
                        clearInterval(id);
                        return;
                    }
                    tries++;
                    if(tries >= maxTries) clearInterval(id);
                }catch(e){ clearInterval(id); }
            }, 100);
        }catch(e){}
    })();

function addList(id, options){
    let content = ``;
    for(let i in options){
        content += `<option>${options[i]}</option>`;
    }

    return `<select class="setting-list" id="${id}">${content}</select>`
}

function addSetting(id){
    return `<input type="checkbox" class="menu_checkbox" id="${id}" ${settings[id] ? "checked" : ""}>`;
}

function addTextInput(id, maxlength){
    return `<input type="text" class="menu_input" placeholder="NONE" id="${id}" value="${settings[id]}" maxlength="${maxlength}">`;
}

function addColorInput(id){
    // Ensure there's a string value for color
    var val = settings[id] || '#ffffff';
    return `<input type="color" class="menu_color" id="${id}" value="${val}">`;
}

function addSelect(id, options, selected){
    let html = `<select id="${id}" class="menu_select">`;
    for(let i=0;i<options.length;i++){
        let val = options[i];
        let sel = (selected && selected == val) ? ' selected' : '';
        // If value is numeric show as x<value>, otherwise show the string (capitalize first letter)
        let label;
        if(typeof val === 'number') label = 'x' + val;
        else if(typeof val === 'string') label = val.charAt(0).toUpperCase() + val.slice(1);
        else label = String(val);
        html += `<option value="${val}"${sel}>${label}</option>`;
    }
    html += `</select>`;
    return html;
}
function saveSettings() {
    // Salva tutti i settings correnti nel localStorage
    for (let key in settings) {
        const input = document.getElementById(key);
        if (input) {
            if (input.type === 'checkbox') {
                settings[key] = input.checked;
            } else {
                settings[key] = input.value !== "" ? parseFloat(input.value) || input.value : settings[key];
            }
            // Log interactive changes for preplacer/autoplacer keys to help debugging
            try{
                if(typeof key === 'string'){
                    // PREPLACER keys
                    if(key.indexOf('preplacer_') === 0){
                        if(key === 'preplacer_debug'){
                            if(settings[key]) console.log('[Mod] preplacer_debug enabled');
                        } else {
                            var dbgEl = document.getElementById('preplacer_debug');
                            var dbg = (dbgEl && dbgEl.type === 'checkbox') ? dbgEl.checked : settings.preplacer_debug;
                            if(dbg) console.log('[Mod] preplacer changed:', key, '=>', settings[key]);
                        }
                    }

                    // AUTOPLACER keys
                    if(key.indexOf('autoplacer_') === 0 || key === 'autoplacer_debug'){
                        if(key === 'autoplacer_debug'){
                                if(settings[key]){
                                    console.log('[Mod] autoplacer_debug enabled');
                                    try{
                                        console.log('[Mod] Autoplacer current values:');
                                        ['spiketrick_distance','spiketrick_linelength','spiketrick_areascale','trap_detection_range','player_enemy_maxdist','spike_min_distance','max_spike_count','anglesvalue'].forEach(k => {
                                            console.log('  ', k, ':', settings[k]);
                                        });
                                    }catch(e){}
                                }
                        } else {
                            var adbgEl = document.getElementById('autoplacer_debug');
                            var adbg = (adbgEl && adbgEl.type === 'checkbox') ? adbgEl.checked : settings.autoplacer_debug;
                            if(adbg) console.log('[Mod] autoplacer changed:', key, '=>', settings[key]);
                        }
                    }
                }
            }catch(e){}
        }
    }
    localStorage.setItem('modSettings', JSON.stringify(settings));
    // Ensure runtime toggle follows persisted setting
    try{ autoVelocityTickToggled = !!settings.autoVelocityTick; }catch(e){}
    // Reflect myplayer_stats HUD immediately after saving settings
    if(typeof updateMyPlayerHUD === 'function') updateMyPlayerHUD();
}

function loadSettings() {
    // Carica settings dal localStorage se esistono
    const savedSettings = localStorage.getItem('modSettings');
    if (savedSettings) {
        const parsed = JSON.parse(savedSettings);
        // Merge con i settings di default
        settings = { ...settings, ...parsed };
    }

    // Applica i valori caricati ai campi del menu
    for (let key in settings) {
        const input = document.getElementById(key);
        if (input) {
            if (input.type === 'checkbox') {
                input.checked = settings[key];
            } else {
                input.value = settings[key];
            }
        }
    }
}

// Funzione per auto-salvare quando cambiano i valori
function setupAutoSave() {
    for (let key in settings) {
        const input = document.getElementById(key);
        if (input) {
            input.addEventListener('change', saveSettings);
            input.addEventListener('input', saveSettings); // Per input text
        }
    }
}

// Funzione getPreplacerValue aggiornata per usare settings salvati
function getPreplacerValue(settingName) {
    const input = document.getElementById(settingName);
    if (input && input.value !== "") {
        return parseFloat(input.value);
    }
    return settings[settingName];
}

// Inizializzazione - da chiamare dopo aver creato il menu
function initializeSettings() {
    loadSettings(); // Carica settings salvati
    setupAutoSave(); // Setup auto-salvataggio
    // Apply auto velocity tick runtime flag from settings
    try{ autoVelocityTickToggled = !!settings.autoVelocityTick; }catch(e){}
    // Wire zoom select to apply saved zoom and listen for changes
    setTimeout(function(){ // run after menu elements created
        var gz = document.getElementById('gamezoom');
        if(gz){
            // If saved settings.gamezoom exists, try to set select
            if(settings.gamezoom){
                // ensure string vs number matching
                var val = parseFloat(settings.gamezoom);
                // pick closest option if exact not present
                var found = false;
                for(var i=0;i<gz.options.length;i++){
                    if(parseFloat(gz.options[i].value) == val){ gz.selectedIndex = i; found = true; break; }
                }
                if(!found) gz.value = val;
            }
            gz.addEventListener('change', function(){
                var val = parseFloat(this.value);
                console.log('[Mod] gamezoom changed to', val);
                settings.gamezoom = val;
                resetZoom();
                saveSettings();
                try { addChatLog('Zoom set to x' + val, '#ffff66'); } catch(e) {}
            });
            // apply current value
            resetZoom();
        }
        // Wire preplacer mode select
        var pm = document.getElementById('preplacer_mode');
        if(pm){
            if(settings.preplacer_mode){
                try{ pm.value = settings.preplacer_mode; }catch(e){}
            }
            pm.addEventListener('change', function(){
                settings.preplacer_mode = this.value;
                try{ saveSettings(); }catch(e){}
                try{ addChatLog('PrePlacer mode set to: ' + this.value, '#cfe9ff'); }catch(e){}
            });
        }
    }, 50);

    // Debug: print current preplacer settings after initialization only if debug enabled
    try{
        var dbgInitEl = document.getElementById('preplacer_debug');
        var dbgInit = (dbgInitEl && dbgInitEl.type === 'checkbox') ? dbgInitEl.checked : settings.preplacer_debug;
        if(dbgInit){
            console.log('[Mod] Preplacer initial values:');
            ['preplacer_activation_distance','preplacer_max_range','preplacer_projection_distance','preplacer_trap_range','preplacer_spike_distance','preplacer_spike_limit'].forEach(k => {
                console.log('  ', k, ':', settings[k]);
            });
        }
    }catch(e){}

    // Debug: print current autoplacer settings after initialization only if autoplacer debug enabled
    try{
        var adbgInitEl = document.getElementById('autoplacer_debug');
        var adbgInit = (adbgInitEl && adbgInitEl.type === 'checkbox') ? adbgInitEl.checked : settings.autoplacer_debug;
        if(adbgInit){
            console.log('[Mod] Autoplacer initial values:');
            ['spiketrick_distance','spiketrick_linelength','spiketrick_areascale','trap_detection_range','player_enemy_maxdist','spike_min_distance','max_spike_count','anglesvalue'].forEach(k => {
                console.log('  ', k, ':', settings[k]);
            });
        }
    }catch(e){}
}

