// --- MyPlayer Stats HUD (styled card in top-left slightly below the corner) ---
function ensureMyPlayerHUD(){
    let hud = document.getElementById('myplayer_stats_hud');
    if(!hud){
        hud = document.createElement('div');
        hud.id = 'myplayer_stats_hud';
        // Base placement & sizing
        hud.style.position = 'fixed';
        hud.style.left = '12px';
        hud.style.top = '56px'; // slightly below the top-left corner
        hud.style.width = '260px';
        hud.style.minHeight = '64px';
        hud.style.zIndex = 99999;
        hud.style.padding = '10px';
        hud.style.boxSizing = 'border-box';
        hud.style.fontFamily = 'Inter, Arial, sans-serif';
        hud.style.fontSize = '13px';
        hud.style.lineHeight = '1.25';

        // Visual style: dark glass card with neon accent and soft glow
        hud.style.background = 'linear-gradient(180deg, rgba(8,10,14,0.96), rgba(6,8,12,0.92))';
        hud.style.borderRadius = '10px';
        hud.style.border = '1px solid rgba(255,255,255,0.04)';
        hud.style.boxShadow = '0 8px 24px rgba(0,0,0,0.6), 0 0 18px rgba(115,79,255,0.06)';
        hud.style.color = '#e6e6ff';
        hud.style.overflow = 'hidden';

        // Transitions for show/hide
        hud.style.transition = 'opacity 180ms cubic-bezier(.2,.9,.2,1), transform 180ms cubic-bezier(.2,.9,.2,1)';
        hud.style.opacity = '0';
        hud.style.transform = 'translateY(-6px)';

        // Inner structure: header + body
        hud.innerHTML = `
            <div id="myplayer_stats_hud_header" style="display:flex;align-items:center;justify-content:space-between;padding-bottom:6px;">
                <div style="display:flex;align-items:center;gap:8px;">
                    <div style="width:10px;height:10px;border-radius:3px;background:linear-gradient(135deg,#8f7bff,#5ce1ff);box-shadow:0 0 10px rgba(143,123,255,0.35);"></div>
                    <div style="font-weight:600;color:#fff;font-size:13px">MyPlayer</div>
                </div>
                <div style="font-size:11px;opacity:0.7;color:#cfcfff">Stats</div>
            </div>
            <pre id="myplayer_stats_hud_body" style="margin:0;padding:0;font-family:ui-monospace, SFMono-Regular, Menlo, Monaco, monospace;color:#cfe9ff;white-space:pre-wrap;">Loading...</pre>
        `;

        document.body.appendChild(hud);
    }
    return hud;
}

let myPlayerHUDInterval = null;
// Track last known alive state so we can detect spawn (dead -> alive) transitions
let _myPlayerHUDLastAlive = null;
function updateMyPlayerHUD(){
    const hud = ensureMyPlayerHUD();
    // Static name maps for hats and accessories (fallback when runtime store arrays aren't globally accessible)
    const HAT_NAME_MAP = {
        45: "Shame!",51: "Moo Cap",50: "Apple Cap",28: "Moo Head",29: "Pig Head",30: "Fluff Head",
        36: "Pandou Head",37: "Bear Head",38: "Monkey Head",44: "Polar Head",35: "Fez Hat",42: "Enigma Hat",
        43: "Blitz Hat",49: "Bob XIII Hat",57: "Pumpkin",8: "Bummle Hat",2: "Straw Hat",15: "Winter Cap",
        5: "Cowboy Hat",4: "Ranger Hat",18: "Explorer Hat",31: "Flipper Hat",1: "Marksman Cap",10: "Bush Gear",
        48: "Halo",6: "Soldier Helmet",23: "Anti Venom Gear",13: "Medic Gear",9: "Miners Helmet",32: "Musketeer Hat",
        7: "Bull Helmet",22: "Emp Helmet",12: "Booster Hat",26: "Barbarian Armor",21: "Plague Mask",46: "Bull Mask",
        14: "Windmill Hat",11: "Spike Gear",53: "Turret Gear",20: "Samurai Armor",58: "Dark Knight",27: "Scavenger Gear",
        40: "Tank Gear",52: "Thief Gear",55: "Bloodthirster",56: "Assassin Gear"
    };
    const ACC_NAME_MAP = {
        12: "Snowball",9: "Tree Cape",10: "Stone Cape",3: "Cookie Cape",8: "Cow Cape",11: "Monkey Tail",
        17: "Apple Basket",6: "Winter Cape",4: "Skull Cape",5: "Dash Cape",2: "Dragon Cape",1: "Super Cape",
        7: "Troll Cape",14: "Thorns",15: "Blockades",20: "Devils Tail",16: "Sawblade",13: "Angel Wings",
        19: "Shadow Wings",18: "Blood Wings",21: "Corrupt X Wings"
    };
    const enabled = !!settings.myplayer_stats;
    // animate in/out
    if(enabled){
        hud.style.display = 'block';
        // small delay to allow display to apply before transition
        requestAnimationFrame(()=>{ hud.style.opacity = '1'; hud.style.transform = 'translateY(0)'; });
    } else {
        hud.style.opacity = '0';
        hud.style.transform = 'translateY(-6px)';
        // hide after transition to avoid pointer issues
        setTimeout(()=>{ if(!settings.myplayer_stats) hud.style.display = 'none'; }, 200);
        // stop periodic updates when disabled
        if(myPlayerHUDInterval){ clearInterval(myPlayerHUDInterval); myPlayerHUDInterval = null; }
        return;
    }

    // If enabled and we don't already have a periodic updater, start one so the HUD can pick up myPlayer when it appears
    if(enabled && !myPlayerHUDInterval){
        myPlayerHUDInterval = setInterval(()=>{ updateMyPlayerHUD(); }, 250);
    }

    // Build content (placeholder / best-effort attempt to extract local player data)
    let content = '';
    // Prefer the explicitly exposed global reference if present (set where myPlayer is assigned)
    const p = (typeof window !== 'undefined' && window.__myPlayer) ? window.__myPlayer :
              (typeof myPlayer !== 'undefined' && myPlayer) ? myPlayer :
              (typeof player !== 'undefined' && player) ? player :
              (typeof localPlayer !== 'undefined' && localPlayer) ? localPlayer : null;

    // Detect dead -> alive transition and show a reminder toast when we spawn
    const nowAlive = !!(p && p.alive !== false);
    if(!_myPlayerHUDLastAlive && nowAlive){
        // show a short reminder to toggle AutoGrind (user requested message)
        showModToast('Reminder: press G to enable AutoGrind', 2200);
    }
    _myPlayerHUDLastAlive = nowAlive;

    if(p){
        // If the player object exists but is not alive, show the same "no live player" placeholder
        if(p.alive === false){
            content += 'No live player object detected.\nThis is a styled placeholder.';
        } else {
            // Compute speed using the same logic as startSpeedLogger():
            // - if x2/y2 exist, use (xVel - x2) and (yVel - y2)
            // - otherwise use xVel/yVel magnitude
            let spVal = null;
            if(typeof p.x2 !== 'undefined' && typeof p.y2 !== 'undefined'){
                const vx = (p.xVel || 0) - (p.x2 || 0);
                const vy = (p.yVel || 0) - (p.y2 || 0);
                spVal = Math.sqrt(vx*vx + vy*vy);
            } else if(typeof p.xVel !== 'undefined' && typeof p.yVel !== 'undefined'){
                spVal = Math.sqrt(Math.pow(p.xVel||0,2) + Math.pow(p.yVel||0,2));
            }

            if(typeof spVal === 'number'){
                content += 'Speed: ' + Math.round(spVal);
            } else {
                content += 'Speed: N/A';
            }
            // Determine which weapon is equipped (primary or secondary)
            var equipText = 'Equipped: Unknown';
            if(p && p.weapons && (p.weaponIndex !== undefined)){
                if(p.weaponIndex === p.weapons[0]) equipText = 'Equipped: Primary';
                else if(p.weaponIndex === p.weapons[1]) equipText = 'Equipped: Secondary';
            }
            content += '\n' + equipText;
            // Show grind variant status for Primary and Secondary (0: Not Grinded, 1: Gold, 2: Diamond, 3: Ruby)
            function variantName(v){ if(v === 0) return 'Not Grinded'; if(v === 1) return 'Gold'; if(v === 2) return 'Diamond'; if(v === 3) return 'Ruby'; return 'Unknown'; }
            var primStat = 'Unknown';
            var secStat = 'Unknown';
            if(p && p.weapons && p.weaponVariants){
                var primId = p.weapons[0];
                var secId = p.weapons[1];
                var primV = (typeof p.weaponVariants[primId] !== 'undefined') ? p.weaponVariants[primId] : null;
                var secV = (typeof p.weaponVariants[secId] !== 'undefined') ? p.weaponVariants[secId] : null;
                primStat = variantName(primV);
                secStat = variantName(secV);
            }
            content += '\nPrimary: ' + primStat + '\nSecondary: ' + secStat;
            // Append a list of owned weapons (names) below the equipped status.
            const weaponsData = (typeof window !== 'undefined' && window.items && window.items.weapons) ? window.items.weapons :
                                (typeof items !== 'undefined' && items.weapons) ? items.weapons : null;
            const hardMap = {0:'tool hammer',1:'hand axe',2:'great axe',3:'short sword',4:'katana',5:'polearm',6:'bat',7:'daggers',8:'stick',9:'hunting bow',10:'great hammer',11:'wooden shield',12:'crossbow',13:'repeater crossbow',14:'mc grabby',15:'musket'};
            if(p && Array.isArray(p.weapons) && p.weapons.length){
                function titleCase(s){ if(!s) return s; return (''+s).split(/\s+/).map(function(w){ return w.charAt(0).toUpperCase() + w.slice(1); }).join(' '); }
                const owned = p.weapons.map(function(wid){
                    var n = null;
                    if(weaponsData && Array.isArray(weaponsData)){
                        for(var _i=0; _i<weaponsData.length; _i++){ var ww = weaponsData[_i]; if(ww && (ww.id === wid || ww.indx === wid)){ n = ww.name; break; } }
                    }
                    if(!n && hardMap[wid]) n = hardMap[wid];
                    if(n) return titleCase(n);
                    return 'id:'+wid;
                }).filter(Boolean);
                if(owned.length) content += '\nWeapons: ' + owned.join(', ');
                // Show autobought Hats / Accessories based on flags set in AUTOBUY (placed directly below Weapons)
                const autobuyMap = [
                        ['__gold600Logged','Winter Cap'],
                        ['__gold2000Logged','Monkey Tail'],
                        ['__gold2500Logged','Flipper'],
                        ['__gold4000Logged','Soldier'],
                        ['__gold6000Logged','Bull'],
                        ['__gold6Logged','Booster'],
                        ['__gold10Logged','Turret'],
                        ['__gold15Logged','Tank'],
                        ['__gold101Logged','Shadow']
                        ['__gold20000Logged','Corrupt X Wings']
                    ];
                const bought = [];
                for(var k=0;k<autobuyMap.length;k++){
                    var flag = autobuyMap[k][0];
                    var name = autobuyMap[k][1];
                    if(p && p[flag]) bought.push(name);
                }
                if(bought.length === autobuyMap.length){
                    content += '\nAll Hats and Accessories Bought';
                } else {
                    content += '\nBought Hats / Accessories: ' + (bought.length? bought.join(', ') : 'None');
                }
                // Detect currently equipped Hat and Accessory with heuristics
                var hatText = 'Unknown';
                var accText = 'Unknown';
                // Prefer obvious fields
                if(typeof p.latestSkin !== 'undefined') hatText = p.latestSkin;
                if(typeof p.latestTail !== 'undefined') accText = p.latestTail;

                // If still unknown, probe for likely property names on the player object
                function probeEquip(obj){
                    var res = {hat: null, acc: null, found: []};
                    var keys = Object.keys(obj || {});
                    keys.forEach(function(k){
                        var low = k.toLowerCase();
                        if(/latest|current|equipp?ed|skin|hat/.test(low) && res.hat === null){ res.hat = obj[k]; res.found.push(k+':'+obj[k]); }
                        if(/latest|current|equipp?ed|tail|access|acc|t?ail/.test(low) && res.acc === null){ res.acc = obj[k]; res.found.push(k+':'+obj[k]); }
                    });
                    return res;
                }

                if(hatText === 'Unknown' || accText === 'Unknown'){
                    var probe = probeEquip(p);
                    if(hatText === 'Unknown' && probe.hat !== null) hatText = probe.hat;
                    if(accText === 'Unknown' && probe.acc !== null) accText = probe.acc;
                    // If still unknown, but we discovered some candidate keys, show them for diagnostics
                    if((hatText === 'Unknown' || accText === 'Unknown') && probe.found.length){
                        // append a compact diagnostic so you can see what fields exist on the runtime player object
                        content += '\n[Detected fields: ' + probe.found.slice(0,6).join(', ') + (probe.found.length>6? '...':'') + ']';
                    }
                }

                // Try to resolve numeric ids to human-friendly names using known store arrays
                function resolveName(id, type, candidates){
                    if(id === null || typeof id === 'undefined') return 'Unknown';
                    var n = id;
                    // If the value is like "latestSkin:45" from probe, try to extract a number
                    var m = (''+id).match(/-?\d+/); if(m) n = Number(m[0]);
                    // If numeric zero => None
                    if(typeof n === 'number' && n === 0) return 'None';
                    // Prefer static map lookup: choose map based on requested type
                    if(type === 'hat' && typeof HAT_NAME_MAP !== 'undefined' && HAT_NAME_MAP[n]) return HAT_NAME_MAP[n];
                    if(type === 'acc' && typeof ACC_NAME_MAP !== 'undefined' && ACC_NAME_MAP[n]) return ACC_NAME_MAP[n];
                    // Fall back to checking other stores; prefer lists matching the type
                    var lists = [];
                    if(type === 'hat' && typeof window !== 'undefined' && window.items && window.items.hats) lists.push(window.items.hats);
                    if(type === 'acc' && typeof window !== 'undefined' && window.items && window.items.accessories) lists.push(window.items.accessories);
                    if(typeof hats !== 'undefined') lists.push(hats);
                    if(typeof accessories !== 'undefined') lists.push(accessories);
                    if(typeof store !== 'undefined' && store.hats) lists.push(store.hats);
                    if(Array.isArray(candidates)) lists = candidates.concat(lists);
                    // If type is accessory, prefer accessory arrays first
                    if(type === 'acc'){
                        // ensure accessory arrays are checked first
                        lists.sort(function(a,b){ return 0; });
                    }
                    for(var L=0; L<lists.length; L++){
                        var lst = lists[L];
                        if(!Array.isArray(lst)) continue;
                        for(var i=0;i<lst.length;i++){ var it = lst[i]; if(!it) continue; if(it.id === n || it.id == n || it.indx === n) return it.name; }
                    }
                    // If not found, return the raw id string
                    return (typeof n === 'number') ? ('id:' + n) : (''+id);
                }
                var hatName = resolveName(hatText, 'hat');
                var accName = resolveName(accText, 'acc');
                content += '\nHat: ' + hatName + '\nAccessory: ' + accName;
                //Autogrind hud status
                if(autoGrind)
                {
                    content += '\nAutogrind: Enabled';
                    if(hasTurrets)
                    {
                        content += '\nPlayer has Turrets';
                        if(!enemyNear)
                        {
                            if(isNearTurretstoBreak)
                            {
                                content += '\nTurret 1 HP: '+turret1hp;
                                content += '\nTurret 2 HP: '+turret2hp;
                                content += '\nTurret 1 ID: '+turret1id;
                                content += '\nTurret 2 ID: '+turret2id;
                                if(ShouldAutoGrindPrimary)
                                    content += '\nAutogrinding Primary';
                                if(ShouldAutoGrindHammer)
                                    content += '\nAutogrinding Hammer';
                                if(ShouldAutoGrindPrimaryWithHammer)
                                    content += '\nAutogrinding Primary with Hammer';
                            }
                        }
                        else
                            content += '\nStopping, Enemy Nearby';
                    }
                    else content += '\nPlayer doesnt have Turrets';
                }
                if(isVelTickActive)
                {
                    content += 'Performing a velocity tick.';
                }
                 content += '\nDamage Prediction: '+ PredictedDamage;
                if(enemyTrapped){
                    content += '\nEnemy currently trapped.';
                }
            }
        }
    } else if(typeof players !== 'undefined' && Array.isArray(players)){
        const local = players.find(pp => pp && (pp.isSelf || pp.id === playerId)) || players[0];
        if(local){
            if(local.alive === false){
                content += 'No live player object detected.\nThis is a styled placeholder.';
            } else {
                let spVal = null;
                if(typeof local.x2 !== 'undefined' && typeof local.y2 !== 'undefined'){
                    const vx = (local.xVel || 0) - (local.x2 || 0);
                    const vy = (local.yVel || 0) - (local.y2 || 0);
                    spVal = Math.sqrt(vx*vx + vy*vy);
                } else if(typeof local.xVel !== 'undefined' && typeof local.yVel !== 'undefined'){
                    spVal = Math.sqrt(Math.pow(local.xVel||0,2) + Math.pow(local.yVel||0,2));
                }

                if(typeof spVal === 'number'){
                    content += 'Speed: ' + Math.round(spVal);
                } else {
                    content += 'Speed: N/A';
                }
                // Determine which weapon is equipped for the players[] fallback
                var equipText2 = 'Equipped: Unknown';
                if(local && local.weapons && (local.weaponIndex !== undefined)){
                    if(local.weaponIndex === local.weapons[0]) equipText2 = 'Equipped: Primary';
                    else if(local.weaponIndex === local.weapons[1]) equipText2 = 'Equipped: Secondary';
                }
                content += '\n' + equipText2;
                // Show grind variant status for Primary and Secondary for players[] fallback
                function variantName2(v){ if(v === 0) return 'Not Grinded'; if(v === 1) return 'Gold'; if(v === 2) return 'Diamond'; if(v === 3) return 'Ruby'; return 'Unknown'; }
                var primStat2 = 'Unknown';
                var secStat2 = 'Unknown';
                if(local && local.weapons && local.weaponVariants){
                    var primId2 = local.weapons[0];
                    var secId2 = local.weapons[1];
                    var primV2 = (typeof local.weaponVariants[primId2] !== 'undefined') ? local.weaponVariants[primId2] : null;
                    var secV2 = (typeof local.weaponVariants[secId2] !== 'undefined') ? local.weaponVariants[secId2] : null;
                    primStat2 = variantName2(primV2);
                    secStat2 = variantName2(secV2);
                }
                content += '\nPrimary: ' + primStat2 + '\nSecondary: ' + secStat2;
                // Show autobought Hats / Accessories for players[] fallback
                const autobuyMap2 = [
                    ['__gold600Logged','Winter Cap'],
                    ['__gold2000Logged','Monkey Tail'],
                    ['__gold2500Logged','Flipper'],
                    ['__gold4000Logged','Soldier'],
                    ['__gold6000Logged','Bull'],
                    ['__gold6Logged','Booster'],
                    ['__gold10Logged','Turret'],
                    ['__gold15Logged','Tank'],
                    ['__gold101Logged','Shadow']
                    ['__gold20000Logged','Corrupt X Wings']
                ];
                const bought2 = [];
                for(var kk=0; kk<autobuyMap2.length; kk++){
                    var flag2 = autobuyMap2[kk][0];
                    var name2 = autobuyMap2[kk][1];
                    if(local && local[flag2]) bought2.push(name2);
                }
                content += '\nBought Hats / Accessories: ' + (bought2.length? bought2.join(', ') : 'None');
                // Append owned weapons list for players[] fallback
                const weaponsData2 = (typeof window !== 'undefined' && window.items && window.items.weapons) ? window.items.weapons :
                                    (typeof items !== 'undefined' && items.weapons) ? items.weapons : null;
                const hardMap2 = {0:'tool hammer',1:'hand axe',2:'great axe',3:'short sword',4:'katana',5:'polearm',6:'bat',7:'daggers',8:'stick',9:'hunting bow',10:'great hammer',11:'wooden shield',12:'crossbow',13:'repeater crossbow',14:'mc grabby',15:'musket'};
                if(local && Array.isArray(local.weapons) && local.weapons.length){
                    function titleCase2(s){ if(!s) return s; return (''+s).split(/\s+/).map(function(w){ return w.charAt(0).toUpperCase() + w.slice(1); }).join(' '); }
                    const owned2 = local.weapons.map(function(wid){
                        var n = null;
                        if(weaponsData2 && Array.isArray(weaponsData2)){
                            for(var _j=0; _j<weaponsData2.length; _j++){ var ww2 = weaponsData2[_j]; if(ww2 && (ww2.id === wid || ww2.indx === wid)){ n = ww2.name; break; } }
                        }
                        if(!n && hardMap2[wid]) n = hardMap2[wid];
                        if(n) return titleCase2(n);
                        return 'id:'+wid;
                    }).filter(Boolean);
                    if(owned2.length) content += '\nWeapons: ' + owned2.join(', ');
                    // Show autobought Hats / Accessories for players[] fallback (placed directly below Weapons)
                    const autobuyMap3 = [
                        ['__gold600Logged','Winter Cap'],
                        ['__gold2000Logged','Monkey Tail'],
                        ['__gold2500Logged','Flipper'],
                        ['__gold4000Logged','Soldier'],
                        ['__gold6000Logged','Bull'],
                        ['__gold6Logged','Booster'],
                        ['__gold10Logged','Turret'],
                        ['__gold20000Logged','Accessory 21'],
                        ['__gold15Logged','Tank'],
                        ['__gold101Logged','Shadow']
                        ['__gold20000Logged','Corrupt X Wings']
                    ];
                    const bought3 = [];
                    for(var kk=0; kk<autobuyMap3.length; kk++){
                        var flag3 = autobuyMap3[kk][0];
                        var name3 = autobuyMap3[kk][1];
                        if(local && local[flag3]) bought3.push(name3);
                    }
                    if(bought3.length === autobuyMap3.length){
                        content += '\nAll Hats and Accessories Bought';
                    } else {
                        content += '\nBought Hats / Accessories: ' + (bought3.length? bought3.join(', ') : 'None');
                    }
                    // Detect currently equipped Hat and Accessory for players[] fallback with heuristics
                    var hatText2 = 'Unknown';
                    var accText2 = 'Unknown';
                    if(typeof local.latestSkin !== 'undefined') hatText2 = local.latestSkin;
                    if(typeof local.latestTail !== 'undefined') accText2 = local.latestTail;

                    function probeEquip2(obj){
                        var res = {hat: null, acc: null, found: []};
                        var keys = Object.keys(obj || {});
                        keys.forEach(function(k){
                            var low = k.toLowerCase();
                            if(/latest|current|equipp?ed|skin|hat/.test(low) && res.hat === null){ res.hat = obj[k]; res.found.push(k+':'+obj[k]); }
                            if(/latest|current|equipp?ed|tail|access|acc|t?ail/.test(low) && res.acc === null){ res.acc = obj[k]; res.found.push(k+':'+obj[k]); }
                        });
                        return res;
                    }

                    if(hatText2 === 'Unknown' || accText2 === 'Unknown'){
                        var probe2 = probeEquip2(local);
                        if(hatText2 === 'Unknown' && probe2.hat !== null) hatText2 = probe2.hat;
                        if(accText2 === 'Unknown' && probe2.acc !== null) accText2 = probe2.acc;
                        if((hatText2 === 'Unknown' || accText2 === 'Unknown') && probe2.found.length){
                            content += '\n[Detected fields: ' + probe2.found.slice(0,6).join(', ') + (probe2.found.length>6? '...':'') + ']';
                        }
                    }

                    function resolveName2(id, candidates){
                        if(id === null || typeof id === 'undefined') return 'Unknown';
                        var n = id;
                        var m = (''+id).match(/-?\d+/); if(m) n = Number(m[0]);
                        if(typeof HAT_NAME_MAP !== 'undefined' && HAT_NAME_MAP[n]) return HAT_NAME_MAP[n];
                        if(typeof ACC_NAME_MAP !== 'undefined' && ACC_NAME_MAP[n]) return ACC_NAME_MAP[n];
                        var lists = [];
                        if(typeof window !== 'undefined' && window.items && window.items.hats) lists.push(window.items.hats);
                        if(typeof window !== 'undefined' && window.items && window.items.accessories) lists.push(window.items.accessories);
                        if(typeof hats !== 'undefined') lists.push(hats);
                        if(typeof accessories !== 'undefined') lists.push(accessories);
                        if(typeof store !== 'undefined' && store.hats) lists.push(store.hats);
                        if(Array.isArray(candidates)) lists = candidates.concat(lists);
                        for(var L=0; L<lists.length; L++){
                            var lst = lists[L];
                            if(!Array.isArray(lst)) continue;
                            for(var i=0;i<lst.length;i++){ var it = lst[i]; if(!it) continue; if(it.id === n || it.id == n || it.indx === n) return it.name; }
                        }
                        return (typeof n === 'number') ? ('id:' + n) : (''+id);
                    }
                    var hatName2 = resolveName2(hatText2, 'hat');
                    var accName2 = resolveName2(accText2, 'acc');
                    content += '\nHat: ' + hatName2 + '\nAccessory: ' + accName2;
                }
            }
        }
    } else {
        content += 'No player data available.';
    }

    const body = document.getElementById('myplayer_stats_hud_body');
    if(body) body.textContent = content;
}

