//APRI MENU TASTO
document.addEventListener("keydown", function(e){
    // Skip if our capture-phase handler already handled this Escape event
    try{ if(e._mod_handled) return; }catch(ex){}
    if(e.keyCode == 27){
        try{
            var mm = (typeof menu !== 'undefined' && menu) ? menu : document.getElementById('mod_menu');
            if(!mm) return;
            mm.style.display = (window.getComputedStyle(mm).display == 'block') ? 'none' : 'block';
        }catch(ex){ console.warn('[Mod] document keydown toggle failed', ex); }
    }
});

// Ensure ESC toggles the mod menu even if other handlers stop propagation: use capture phase
window.addEventListener('keydown', function(e){
    if (e.key === 'Escape' || e.keyCode == 27) {
        // Avoid toggling if focus is on an input (like chatbox)
        var active = document.activeElement;
        if (active && (active.tagName === 'INPUT' || active.tagName === 'TEXTAREA' || active.contentEditable === 'true')) return;
        // mark this event so other handlers can ignore it
        try{ e._mod_handled = true; }catch(ex){}
        try{
            console.log('[Mod] ESC pressed - toggling menu');
            // prefer the global menu variable, then element by id
            var m = (typeof menu !== 'undefined' && menu) ? menu : document.getElementById('mod_menu');
            if(!m){
                console.warn('[Mod] menu element not found - creating temporary menu');
                m = document.createElement('div');
                m.id = 'mod_menu';
                m.innerText = 'Mod menu (temporary)';
                document.body.appendChild(m);
                window.menu = m;
            }

            // Diagnostics: parent/DOM/rect/style
            try{
                console.log('[Mod] menu parent:', m.parentElement ? (m.parentElement.id || m.parentElement.tagName) : null);
                console.log('[Mod] in document?', document.contains(m));
                console.log('[Mod] offsetParent:', m.offsetParent);
                console.log('[Mod] rect before toggle:', m.getBoundingClientRect());
                console.log('[Mod] computed before toggle:', window.getComputedStyle(m).cssText || window.getComputedStyle(m));
            }catch(e){}

            var isOpen = (m.style.display == 'block' || window.getComputedStyle(m).display == 'block');

            if(!isOpen){
                // OPEN: force visible, centered, above all, and focus
                m.style.position = 'fixed';
                m.style.left = '50%';
                m.style.top = '50%';
                m.style.transform = 'translate(-50%, -50%)';
                m.style.background = 'rgba(39, 39, 39, 1)';
                m.style.padding = '0px';
                m.style.zIndex = '2147483647';
                m.style.pointerEvents = 'auto';
                m.style.maxWidth = '90vw';
                m.style.maxHeight = '90vh';
                m.style.overflow = 'auto';
                m.style.display = 'block';
                m.style.visibility = 'visible';
                try{ m.scrollIntoView({block: 'center'}); } catch(e){}
                try{ if(m.tabIndex === undefined) m.tabIndex = -1; m.focus(); } catch(e){}
                console.log('[Mod] menu opened - rect after open:', m.getBoundingClientRect());
                // When opening via ESC, show the Combat settings by default (only first time)
                try{
                    if(!menuOpenedOnce){
                        var ids = ["combat_settings","visual_settings","placers_settings","movement_settings","labels_settings","extra_settings"];
                        ids.forEach(function(id){
                            var el = document.getElementById(id);
                            if(!el) return;
                            el.style.display = (id === "combat_settings") ? 'block' : 'none';
                        });
                        // update sidebar active class if present
                        try{
                            var cats = document.querySelectorAll('.category');
                            cats.forEach(function(c){ c.classList && c.classList.remove('active'); });
                            var combatBtn = document.getElementById('combat');
                            if(combatBtn) combatBtn.classList && combatBtn.classList.add('active');
                        }catch(e){}
                        menuOpenedOnce = true;
                    }
                }catch(e){}
            } else {
                // CLOSE: hide and remove temporary attributes
                m.style.display = 'none';
                // keep it in DOM but invisible
                console.log('[Mod] menu closed');
            }

            // Diagnostics after toggle
            try{ console.log('[Mod] menu now', m.style.display, 'zIndex=', m.style.zIndex, 'computed:', window.getComputedStyle(m).cssText || window.getComputedStyle(m)); } catch(e){}
        }catch(err){ console.error('[Mod] error toggling menu', err); }
    }
}, true);

