for(let setting in settings){
    // only attach listener if the corresponding DOM element exists
    try{
    	// settings handling
        var el = document.getElementById(setting);
        if(!el) continue;
        el.addEventListener("change", function(){
            try{
                if(typeof settings[setting] == "boolean"){
                    if(setting == "chatlog"){
                        if(chatLog.style.display == "none"){
                            chatLog.style.display = "block";
                        } else {
                            chatLog.style.display = "none";
                        }
                    }

                    settings[setting] = document.getElementById(setting).checked;
                } else {
                    settings[setting] = document.getElementById(setting).value;
                }

                // persist settings if function exists
                try{ if(typeof saveSettings === 'function') saveSettings(); }catch(e){}

                // Small fixed "Saved" box in the top-left corner
                try{
                    var box = document.getElementById('mod_saved_box');
                    if(!box){
                        box = document.createElement('div');
                        box.id = 'mod_saved_box';
                        box.innerText = 'Saved';
                        Object.assign(box.style, {
                            position: 'fixed',
                            left: '12px',
                            top: '12px',
                            padding: '8px 12px',
                            background: 'rgba(0,0,0,0.78)',
                            color: '#d49a9aff',
                            borderRadius: '8px',
                            fontSize: '13px',
                            pointerEvents: 'none',
                            zIndex: '2147483647',
                            opacity: '0',
                            transform: 'translateY(-6px)',
                            transition: 'opacity 200ms ease, transform 200ms ease'
                        });
                        document.body.appendChild(box);
                    }
                    // show
                    box.innerText = 'Saved';
                    // reset hide timer if present
                    try{ if(box._hideTimeout) { clearTimeout(box._hideTimeout); box._hideTimeout = null; } }catch(e){}
                    requestAnimationFrame(function(){ box.style.opacity = '1'; box.style.transform = 'translateY(0)'; });
                    // hide after short delay but keep element in DOM for reuse
                    box._hideTimeout = setTimeout(function(){ try{ box.style.opacity = '0'; box.style.transform = 'translateY(-6px)'; }catch(e){} }, 1100);
                }catch(e){}
            }catch(e){}
        });
    }catch(e){ /* element missing or other error - ignore */ }
}

// Transient toast helper used by small UI actions
function showModToast(msg, duration){
    try{
        duration = typeof duration === 'number' ? duration : 1200;
        var id = 'mod_toast_box';
        var t = document.getElementById(id);
        if(!t){
            t = document.createElement('div');
            t.id = id;
            Object.assign(t.style, {
                position: 'fixed',
                // default left; some messages override this below
                left: '75px',
                top: '12px',
                transform: 'translateY(-6px)',
                padding: '8px 12px',
                background: 'rgba(0,0,0,0.78)',
                color: '#ffffff',
                borderRadius: '8px',
                fontSize: '13px',
                pointerEvents: 'none',
                zIndex: '2147483647',
                opacity: '0',
                transition: 'opacity 200ms ease, transform 200ms ease'
            });
            document.body.appendChild(t);
        }
        // All toasts should appear at the same left offset as the Saved box
        try{ t.style.left = '12px'; }catch(e){}
        t.textContent = msg;
        // reset timer if present
        try{ if(t._hideTimeout) { clearTimeout(t._hideTimeout); t._hideTimeout = null; } }catch(e){}
    requestAnimationFrame(function(){ t.style.opacity = '1'; t.style.transform = 'translateY(0)'; });
    t._hideTimeout = setTimeout(function(){ try{ t.style.opacity = '0'; t.style.transform = 'translateY(-6px)'; }catch(e){} }, duration);
    }catch(e){ console.warn('[Mod] showModToast failed', e); }
}




