// Style chat log so it can overlay the game and remain visible in fullscreen
chatLog.style.position = 'fixed';
chatLog.style.right = '10px';
chatLog.style.bottom = '10px';
chatLog.style.width = '320px';
chatLog.style.maxHeight = '40vh';
chatLog.style.overflow = 'auto';
chatLog.style.background = 'rgba(0,0,0,0.6)';
chatLog.style.border = '4px solid rgba(255, 255, 255, 1)';
chatLog.style.padding = '8px';
chatLog.style.zIndex = '2147483647';
chatLog.style.pointerEvents = 'auto';

// Helper to attach chatLog into the element that will appear in fullscreen (if present)
function attachChatLogParent(){
    try{
        var fsContainer = document.getElementById('touch-controls-fullscreen') || document.getElementById('gameCanvas') && document.getElementById('gameCanvas').parentElement;
        if(fsContainer && fsContainer.appendChild){
            fsContainer.appendChild(chatLog);
            // when inside the game container keep absolute positioning so it sits relative to that container
            chatLog.style.position = 'absolute';
            chatLog.style.right = '10px';
            chatLog.style.bottom = '10px';
        } else {
            if(!chatLog.parentNode) document.body.appendChild(chatLog);
            chatLog.style.position = 'fixed';
        }
    }catch(e){ if(!chatLog.parentNode) document.body.appendChild(chatLog); }
}

attachChatLogParent();

// Re-attach when fullscreen changes (some pages move the canvas into a fullscreen element)
document.addEventListener('fullscreenchange', function(){
    try{
        var el = document.fullscreenElement || document.getElementById('touch-controls-fullscreen');
        if(el && el.appendChild){
            el.appendChild(chatLog);
            chatLog.style.position = 'absolute';
        } else {
            if(!document.body.contains(chatLog)) document.body.appendChild(chatLog);
            chatLog.style.position = 'fixed';
        }
    }catch(e){}
});

// Ensure the chatlog checkbox reliably toggles the chat log visibility
(function(){
    try{
        var chatToggle = document.getElementById('chatlog');
        if(chatToggle){
            // apply initial state from saved settings or checkbox
            chatLog.style.display = (chatToggle.checked || settings.chatlog) ? 'block' : 'none';
            // restore pinned state / position
            try{
                var pinBtn = document.getElementById('chat_pin');
                if(pinBtn){
                    setPinVisual(settings.chatPinned);
                }
                if(settings.chatLeft !== null && settings.chatTop !== null){
                    chatLog.style.right = 'auto';
                    chatLog.style.left = settings.chatLeft + 'px';
                    chatLog.style.top = settings.chatTop + 'px';
                    chatLog.style.bottom = 'auto';
                }
            }catch(e){}
            // attach listener to keep settings in sync and toggle visibility
            chatToggle.addEventListener('change', function(){
                chatLog.style.display = this.checked ? 'block' : 'none';
                settings.chatlog = this.checked;
                try{ saveSettings(); } catch(e){}
            });
        }
    } catch(e){}
})();

// PIN and DRAG BEHAVIOR
function setPinVisual(pinned){
    var btn = document.getElementById('chat_pin');
    if(!btn) return;
    btn.textContent = pinned ? 'СЂСџвЂњРЉ' : 'СЂСџвЂњРЊ';
}

document.addEventListener('DOMContentLoaded', function(){ /* no-op: keep listener for environments */ });

(function(){
    var pin = document.getElementById('chat_pin');
    if(!pin) return;
    var dragging = false;
    var offsetX = 0, offsetY = 0;

    // initialize visual
    setPinVisual(settings.chatPinned);

    pin.addEventListener('click', function(e){
        settings.chatPinned = !settings.chatPinned;
        setPinVisual(settings.chatPinned);
        try{ saveSettings(); } catch(ex){}
    });

    // start drag from header when not pinned
    var header = document.getElementById('chat_header');
    header.style.cursor = 'move';
    header.addEventListener('pointerdown', function(e){
        if(settings.chatPinned) return;
        dragging = true;
        offsetX = e.clientX - (chatLog.getBoundingClientRect().left || 0);
        offsetY = e.clientY - (chatLog.getBoundingClientRect().top || 0);
        header.setPointerCapture(e.pointerId);
    });
    header.addEventListener('pointermove', function(e){
        if(!dragging) return;
        var left = e.clientX - offsetX;
        var top = e.clientY - offsetY;
        chatLog.style.left = left + 'px';
        chatLog.style.top = top + 'px';
        // ensure it's not anchored to right/bottom
        chatLog.style.right = 'auto';
        chatLog.style.bottom = 'auto';
    });
    header.addEventListener('pointerup', function(e){
        if(!dragging) return;
        dragging = false;
        try{
            settings.chatLeft = parseInt(chatLog.style.left, 10) || 0;
            settings.chatTop = parseInt(chatLog.style.top, 10) || 0;
            saveSettings();
        }catch(e){}
        try{ header.releasePointerCapture(e.pointerId); } catch(e){}
    });
})();

function addChatLog(text, color){
    let time = new Date();
    let minutes = time.getMinutes();
    let hours = time.getHours();
    let seconds = time.getSeconds();

    let chat_message = document.createElement("div");
    chat_message.className = "chat_message";
    chat_message.style.color = `${color}`;
    chat_message.innerText = `[${hours}:${minutes < 10 ? "0" + minutes : minutes}:${seconds < 10 ? "0" + seconds : seconds}] - ${text}`

    document.getElementById("chat_box").appendChild(chat_message);
    chat_message.scrollIntoView({behavior: 'auto', block: 'end'});
}
// MENU STILE
addChatLog("Welcome, God!", "#fffafaff");

let css = document.createElement("style");
css.type = "text/css";
css.appendChild(document.createTextNode(`
/* ------------------
   MOD MENU РІР‚вЂќ Improved UI
   Responsive glassmorphism, cleaner typography and fixed scrollbars
   ------------------ */
:root{
    --menu-bg: rgba(12,14,24,0.55);
    --panel: rgba(20,22,32,0.65);
    --sidebar: rgba(255,255,255,0.02);
    --accent: #6b6fe0;
    --muted: rgba(255,255,255,0.75);
}

#mod_menu{
    position: fixed;
    z-index: 1000000;
    left: 50%;
    top: 50%;
    transform: translate(-50%, -50%);
    width: min(1100px, 95vw);
    height: min(800px, 90vh);
    max-width: 1100px;
    max-height: 900px;
    border-radius: 14px;
    overflow: hidden;
    background: linear-gradient(180deg, rgba(18,20,30,0.72), rgba(10,12,18,0.52));
    backdrop-filter: blur(12px) saturate(120%);
    box-shadow: 0 18px 60px rgba(0,0,0,0.6), inset 0 1px 0 rgba(255,255,255,0.02);
    border: 1px solid rgba(255,255,255,0.04);
    animation: modmenu-fade 320ms ease;
    font-family: Inter, system-ui, -apple-system, 'Segoe UI', Roboto, 'Helvetica Neue', Arial;
    color: var(--muted);
}

/* header area (title + close) */
#name_text{
    display:flex;
    align-items:center;
    justify-content:space-between;
    gap:12px;
    padding: 14px 18px;
    font-size: 20px;
    font-weight: 700;
    color: #fff;
    letter-spacing: 1px;
    text-transform: uppercase;
}

#name_text .subtitle{font-weight:400; font-size:12px; opacity:0.85; text-transform:none; letter-spacing:0}

/* sidebar */
#category_block{
    position: absolute;
    top: 55px;
    left: 12px;
    width: 260px;
    bottom: 12px;
    padding: 12px;
    background: var(--sidebar);
    border-radius: 10px;
    overflow-y: auto;
    border: 1px solid rgba(255, 255, 255, 0.12);
}

.category{
    display:flex;
    align-items:center;
    gap:12px;
    padding:10px 12px;
    margin:8px 4px;
    border-radius:10px;
    cursor:pointer;
    transition: all 180ms ease;
    color: #e6e9ff;
}

.category_icon{ color: var(--accent); font-size:20px }
.category_text{ font-size:14px; font-weight:600 }

.category:hover{ background: linear-gradient(90deg, rgba(107,111,224,0.07), rgba(255,255,255,0.02)); transform: translateX(6px); box-shadow: 0 6px 18px rgba(12,14,30,0.45) }

.category.active{ background: linear-gradient(90deg, rgba(107,111,224,0.12), rgba(255,255,255,0.03)); box-shadow: 0 8px 24px rgba(15,16,40,0.5); transform: translateX(6px) }

#exit{ position: absolute; left:12px; right:12px; bottom:12px; height:48px; display:flex; align-items:center; justify-content:center; background: transparent; border-radius:10px; }
#exit .category_text{ color: #ffbdbd }

/* content panel */
.settings_block{
    position: absolute;
    top: 5px;
    left: 310px; /* sidebar 260 + margin */
    right: 12px;
    bottom: 12px;
    padding: 18px;
    overflow-y: auto;
    background: var(--sidebar);
    border-radius: 10px;
    border: 1px solid rgba(255, 255, 255, 0.12);
}

.settings_title{ color: #8b8b8bff; font-weight:700; margin-bottom:8px; font-size:20px }

.setting2{ margin-bottom:8px }

.setting_element{
    display:flex; align-items:center; justify-content:space-between; gap:12px; padding:10px 12px; border-radius:10px; background: rgba(56, 56, 56, 1);
}
.setting_element:hover{ background: rgba(107,111,224,0.04); box-shadow: 0 6px 18px rgba(12,14,30,0.35) }

.setting_name{ font-size:13px; color: #edf2ff; font-weight:600 }

/* improved toggles */
.menu_checkbox{ appearance:none; width:48px; height:26px; border-radius:999px; background: rgba(255,255,255,0.12); position:relative; cursor:pointer; border:1px solid rgba(0,0,0,0.25) }
.menu_checkbox::after{ content:""; position:absolute; width:20px; height:20px; left:3px; top:3px; border-radius:50%; background:#fff; transition: all 200ms cubic-bezier(.2,.9,.2,1); box-shadow: 0 4px 10px rgba(0,0,0,0.35) }
.menu_checkbox:checked{ background: linear-gradient(90deg,var(--accent), #8f93f9) }
.menu_checkbox:checked::after{ transform: translateX(22px); }

/* inputs & buttons */
input[type='text'], input[type='number'], input[type='color'], select, .menu_button {
    font-family: inherit;
    outline: none;
}

/* pretty form controls aligned to right side of setting rows */
.setting_element input[type='text'], .setting_element input[type='number'], .setting_element select, .setting_element input[type='color']{
    min-width: 220px;
    max-width: 420px;
    width: 36%;
    padding: 8px 10px;
    border-radius: 8px;
    border: 1px solid rgba(255,255,255,0.04);
    background: rgba(255,255,255,0.02);
    color: #f3f6ff;
    box-shadow: inset 0 1px 0 rgba(255,255,255,0.02);
}
.setting_element input[type='color']{ padding:4px; width:64px }
.setting_element input[type='text']::placeholder, .setting_element input[type='number']::placeholder{ color: rgba(255,255,255,0.35) }

/* make native select dropdowns readable on dark menu background */
.setting_element select{
    /* keep the selected value readable */
    color: #f3f6ff;
    background: rgba(255,255,255,0.02);
    border-radius: 8px;
    border: 1px solid rgba(255,255,255,0.04);
    padding-right: 30px; /* leave room for native arrow */
    -webkit-appearance: none;
    appearance: none;
}
.setting_element select option{
    /* dropdown option list (most browsers honor color/background for options) */
    background: #0b1220; /* dark option background */
    color: #f3f6ff; /* light option text */
}
.setting_element select option:checked{
    /* highlighted/selected option in list */
    background: rgba(255,255,255,0.04);
    color: #111827;
}
.setting_element select::-ms-expand{ display: none; }

/* Normalize focus rings РІР‚вЂќ some platforms/browsers show a green system focus outline
   (Windows accent color). Remove it and provide a subtle, consistent focus style. */
#mod_menu input:focus, #mod_menu select:focus, #mod_menu .menu_checkbox:focus, #mod_menu .menu_color:focus, #mod_menu .menu_select:focus {
    outline: none !important;
    box-shadow: none !important;
    border-color: rgba(255,255,255,0.04) !important;
}
#mod_menu input:focus-visible, #mod_menu select:focus-visible, #mod_menu .menu_checkbox:focus-visible {
    outline: none !important;
    /* subtle bluish halo so keyboard users still see focus */
    box-shadow: 0 0 0 4px rgba(107,111,224,0.09) !important;
}

.menu_button{ background: linear-gradient(135deg, rgba(107,111,224,0.14), rgba(60,64,85,0.12)); color:#fff; border-radius:10px; border:1px solid rgba(255,255,255,0.03); padding:10px 14px; cursor:pointer }
.menu_button:hover{ box-shadow: 0 10px 30px rgba(107,111,224,0.12); transform: translateY(-2px) }

/* scrollbars (fixed syntax) */
#mod_menu::-webkit-scrollbar, .settings_block::-webkit-scrollbar, #category_block::-webkit-scrollbar, #chat_box::-webkit-scrollbar { width:10px; height:10px }
#mod_menu::-webkit-scrollbar-track, .settings_block::-webkit-scrollbar-track, #category_block::-webkit-scrollbar-track, #chat_box::-webkit-scrollbar-track { background: transparent }
#mod_menu::-webkit-scrollbar-thumb, .settings_block::-webkit-scrollbar-thumb, #category_block::-webkit-scrollbar-thumb, #chat_box::-webkit-scrollbar-thumb {
    background: linear-gradient(180deg, rgba(110, 110, 110, 0.85), rgba(102, 102, 102, 0.32)); border-radius:10px; box-shadow: inset 0 0 6px rgba(0,0,0,0.4)
}


@keyframes modmenu-fade{ from{ opacity:0; transform: translate(-50%,-52%) scale(.98) } to{ opacity:1; transform: translate(-50%,-50%) scale(1) } }

/* responsive tweaks */
@media (max-width:720px){
    #category_block{ display:flex; flex-direction:row; gap:6px; width:calc(100% - 48px); left:12px; top:52px }
    .settings_block{ left:12px; top:96px; right:12px }
}

`));

